  1→// sidecar/index.ts
  2→// Entry point for the OpenDevs agent-server process.
  3→//
  4→// Supports two transport modes (selected via --listen flag):
  5→//   --listen ws://    → WebSocket server on 127.0.0.1 (default, dynamic port)
  6→//   --listen unix://  → Unix domain socket (legacy, for backward compat)
  7→//
  8→// Both transports use JSON-RPC 2.0 over text frames/lines.
  9→
 10→import * as Sentry from "@sentry/node";
 11→
 12→// Initialize Sentry before anything else.
 13→// DSN passed as env var from Rust process manager (not hardcoded — open source repo).
 14→if (process.env.SENTRY_DSN) {
 15→  Sentry.init({
 16→    dsn: process.env.SENTRY_DSN,
 17→    environment: process.env.NODE_ENV === "production" ? "production" : "development",
 18→    sendDefaultPii: true,
 19→    initialScope: { tags: { process: "sidecar" } },
 20→  });
 21→}
 22→
 23→import * as net from "net";
 24→import * as fs from "fs";
 25→import * as path from "path";
 26→import * as os from "os";
 27→import * as util from "util";
 28→import { exec } from "child_process";
 29→import { StringDecoder } from "string_decoder";
 30→import { createServer as createHttpServer } from "http";
 31→import { WebSocketServer, WebSocket } from "ws";
 32→
 33→import { getErrorMessage } from "../shared/lib/errors";
 34→import { RpcConnection, wsTransport } from "./rpc-connection";
 35→import { EventBroadcaster } from "./event-broadcaster";
 36→import { classifyError } from "./agents/lifecycle";
 37→import { registerAgent, getAgent, initializeAllAgents } from "./agents/registry";
 38→import { ClaudeAgentHandler } from "./agents/claude/claude-handler";
 39→import { CodexAgentHandler } from "./agents/codex/codex-handler";
 40→import {
 41→  handleHttpRequest,
 42→  isShuttingDown,
 43→  setShuttingDown,
 44→  setAgentsInitialized,
 45→  trackSession,
 46→  untrackSession,
 47→  waitForDrain,
 48→  cancelRemainingSessions,
 49→} from "./health";
 50→
 51→// ============================================================================
 52→// Logging
 53→// ============================================================================
 54→
 55→export const logFilePath = `/tmp/opendevs-${process.pid}.log`;
 56→const originalLog = console.log;
 57→
 58→const LOG_LEVEL = (process.env.LOG_LEVEL || "info") as "debug" | "info" | "error";
 59→const LOG_LEVELS = { debug: 0, info: 1, error: 2 };
 60→
 61→function shouldLog(level: "debug" | "info" | "error"): boolean {
 62→  return LOG_LEVELS[level] >= LOG_LEVELS[LOG_LEVEL];
 63→}
 64→
 65→function formatLogArgs(args: any[]): string {
 66→  return args
 67→    .map((arg) => {
 68→      if (typeof arg === "string") return arg;
 69→      if (arg instanceof Error) return `${arg.message}\n${arg.stack || ""}`;
 70→      return util.inspect(arg, { depth: 4, breakLength: Infinity });
 71→    })
 72→    .join(" ");
 73→}
 74→
 75→// Buffered log writer -- avoids synchronous appendFileSync on every log call
 76→let logBuffer = "";
 77→let flushTimer: NodeJS.Timeout | null = null;
 78→
 79→function flushLogs(): void {
 80→  if (logBuffer) {
 81→    fs.appendFileSync(logFilePath, logBuffer);
 82→    logBuffer = "";
 83→  }
 84→  flushTimer = null;
 85→}
 86→
 87→function writeLog(line: string): void {
 88→  logBuffer += line;
 89→  if (!flushTimer) {
 90→    flushTimer = setTimeout(flushLogs, 100);
 91→  }
 92→  if (logBuffer.length > 8192) {
 93→    flushLogs();
 94→  }
 95→}
 96→
 97→// Ensure logs are flushed on shutdown
 98→process.on("exit", flushLogs);
 99→
100→console.log = (...args: any[]) => {
101→  if (!shouldLog("info")) return;
102→  const timestamp = new Date().toISOString();
103→  writeLog(`[${timestamp}] ${formatLogArgs(args)}\n`);
104→};
105→
106→console.error = (...args: any[]) => {
107→  const timestamp = new Date().toISOString();
108→  writeLog(`[${timestamp}] ERROR: ${formatLogArgs(args)}\n`);
109→};
110→
111→console.debug = (...args: any[]) => {
112→  if (!shouldLog("debug")) return;
113→  const timestamp = new Date().toISOString();
114→  writeLog(`[${timestamp}] DEBUG: ${formatLogArgs(args)}\n`);
115→};
116→
117→// ============================================================================
118→// CLI flag parsing
119→// ============================================================================
120→
121→type TransportMode = "ws" | "unix";
122→
123→function parseTransportMode(): TransportMode {
124→  const listenIdx = process.argv.indexOf("--listen");
125→  if (listenIdx === -1) return "ws"; // Default: WebSocket
126→  const value = process.argv[listenIdx + 1] || "";
127→  if (value.startsWith("unix://")) return "unix";
128→  if (value.startsWith("ws://") || value === "") return "ws";
129→  // Unknown scheme — default to ws
130→  console.error(`[CLI] Unknown --listen scheme "${value}", defaulting to ws://`);
131→  return "ws";
132→}
133→
134→// ============================================================================
135→// UnifiedSidecar
136→// ============================================================================
137→
138→class UnifiedSidecar {
139→  private transportMode: TransportMode;
140→  private initializedAgents = new Set<string>();
141→
142→  // Unix socket transport
143→  private socketPath: string;
144→  private unixServer: net.Server | null = null;
145→
146→  // WebSocket transport
147→  private httpServer: ReturnType<typeof createHttpServer> | null = null;
148→  private wss: WebSocketServer | null = null;
149→
150→  constructor(mode: TransportMode) {
151→    this.transportMode = mode;
152→    this.socketPath = path.join(os.tmpdir(), `opendevs-sidecar-${process.pid}.sock`);
153→
154→    console.log(`UnifiedSidecar: Initializing (transport=${mode})...`);
155→
156→    // Graceful shutdown handlers — drain in-flight turns before exiting
157→    const gracefulShutdown = async (signal: string) => {
158→      console.log(`\n[SIGNAL] Received ${signal}, shutting down gracefully...`);
159→
160→      // 1. Stop accepting new turn/start requests
161→      setShuttingDown(true);
162→
163→      // 2. Stop accepting new WS connections (close the HTTP listener)
164→      if (this.httpServer) {
165→        this.httpServer.close();
166→        console.log("[SHUTDOWN] HTTP server closed to new connections");
167→      }
168→      if (this.unixServer) {
169→        this.unixServer.close();
170→        console.log("[SHUTDOWN] Unix server closed to new connections");
171→      }
172→
173→      // 3. Wait for in-flight turns to drain (default 30s timeout)
174→      console.log("[SHUTDOWN] Waiting for in-flight turns to drain...");
175→      const drained = await waitForDrain();
176→      if (drained) {
177→        console.log("[SHUTDOWN] All turns drained successfully");
178→      } else {
179→        console.log("[SHUTDOWN] Drain timeout reached, cancelling remaining sessions");
180→        await cancelRemainingSessions();
181→      }
182→
183→      // 4. Full cleanup (kill child processes, close WS clients)
184→      try {
185→        await this.cleanup();
186→        console.log("[SIGNAL] Cleanup complete, exiting process");
187→      } catch (error) {
188→        console.error("[SIGNAL] Cleanup failed:", error);
189→      } finally {
190→        process.exit(0);
191→      }
192→    };
193→    process.on("SIGINT", () => gracefulShutdown("SIGINT"));
194→    process.on("SIGTERM", () => gracefulShutdown("SIGTERM"));
195→  }
196→
197→  /**
198→   * Wires up all JSON-RPC methods and notifications on a new connection.
199→   * Transport-agnostic — works with both Unix socket and WebSocket tunnels.
200→   */
201→  private setupJsonRpc(rpcTunnel: RpcConnection): void {
202→    EventBroadcaster.attachTunnel(rpcTunnel);
203→
204→    // --- Initialize handshake (backend agent-client sends this) ---
205→    rpcTunnel.addMethod("initialize", () => {
206→      const agents = [];
207→      for (const [agentType, handler] of [
208→        ["claude", getAgent("claude")],
209→        ["codex", getAgent("codex")],
210→      ] as const) {
211→        if (handler && this.initializedAgents.has(agentType)) {
212→          agents.push({
213→            type: agentType,
214→            capabilities: handler.capabilities,
215→            initialized: true,
216→          });
217→        }
218→      }
219→      return { version: "1.0", agents };
220→    });
221→
222→    // --- Initialized notification (backend confirms handshake) ---
223→    rpcTunnel.addMethod("initialized", () => {
224→      console.log("[RPC] Backend handshake complete (initialized)");
225→      return undefined;
226→    });
227→
228→    // --- turn/start (new wire protocol method, maps to query dispatch) ---
229→    rpcTunnel.addMethod("turn/start", async (params: any) => {
230→      const sessionId = params?.sessionId;
231→      const agentType = params?.agentType || "claude";
232→      const prompt = params?.prompt;
233→      const options = params?.options || {};
234→
235→      // Reject new turns during shutdown
236→      if (isShuttingDown()) {
237→        return { accepted: false, reason: "shutting down" };
238→      }
239→
240→      if (!sessionId || !prompt) {
241→        return { accepted: false, reason: "turn/start requires sessionId and prompt" };
242→      }
243→
244→      const agent = getAgent(agentType);
245→      if (!agent) {
246→        return { accepted: false, reason: `No agent registered for type: ${agentType}` };
247→      }
248→
249→      // Track this session for graceful shutdown draining
250→      trackSession(sessionId, agentType);
251→
252→      agent
253→        .query(sessionId, prompt, options)
254→        .catch((err) => {
255→          console.error(`[turn/start] Unhandled error in ${agentType} query:`, err);
256→          const classified = classifyError(err);
257→          EventBroadcaster.sendError({
258→            id: sessionId,
259→            type: "error",
260→            error: classified.message,
261→            agentType,
262→            category: classified.category,
263→          });
264→          EventBroadcaster.emitSessionError(
265→            sessionId,
266→            agentType,
267→            classified.message,
268→            classified.category
269→          );
270→        })
271→        .finally(() => {
272→          // Untrack when the turn completes (success, error, or cancel)
273→          untrackSession(sessionId);
274→        });
275→
276→      EventBroadcaster.emitSessionStarted(sessionId, agentType);
277→
278→      console.log(`[TIMING][turn/start] DISPATCHED session=${sessionId}`);
279→      return { accepted: true };
280→    });
281→
282→    // --- turn/cancel (new wire protocol method, maps to cancel dispatch) ---
283→    rpcTunnel.addMethod("turn/cancel", async (params: any) => {
284→      const sessionId = params?.sessionId;
285→      if (!sessionId) return;
286→
287→      // Try all registered agents — the backend may not send agentType for cancel
288→      for (const agentType of ["claude", "codex"] as const) {
289→        const agent = getAgent(agentType);
290→        if (agent) void agent.cancel(sessionId);
291→      }
292→    });
293→
294→    // --- session/reset (new wire protocol method) ---
295→    rpcTunnel.addMethod("session/reset", (params: any) => {
296→      const sessionId = params?.sessionId;
297→      if (!sessionId) return;
298→
299→      for (const agentType of ["claude", "codex"] as const) {
300→        const agent = getAgent(agentType);
301→        if (agent) agent.reset(sessionId);
302→      }
303→    });
304→
305→    // --- Query (dispatch to agent by agentType) ---
306→    // Returns synchronous ACK/reject before async streaming begins.
307→    // query() is NOT awaited — the ACK returns immediately after validation.
308→    EventBroadcaster.onQuery(rpcTunnel, async (request) => {
309→      // Reject new queries during shutdown
310→      if (isShuttingDown()) {
311→        return { accepted: false, reason: "shutting down" };
312→      }
313→
314→      const tQueryReceived = Date.now();
315→      console.log(
316→        `[TIMING][QUERY] RECEIVED session=${request.id} agent=${request.agentType} promptLength=${request.prompt?.length ?? 0}`
317→      );
318→      const agent = getAgent(request.agentType);
319→      if (!agent) {
320→        return { accepted: false, reason: `No agent registered for type: ${request.agentType}` };
321→      }
322→
323→      // Track this session for graceful shutdown draining
324→      trackSession(request.id, request.agentType);
325→
326→      // The backend saves the user message BEFORE forwarding turn/start to the
327→      // agent-server. The agent-server just receives the query and starts the SDK.
328→      agent
329→        .query(request.id, request.prompt, request.options)
330→        .catch((err) => {
331→          console.error(`[QUERY] Unhandled error in ${request.agentType} query:`, err);
332→          // Recover: notify frontend of the error. The backend handles DB status updates
333→          // via canonical events (session.error).
334→          const classified = classifyError(err);
335→          EventBroadcaster.sendError({
336→            id: request.id,
337→            type: "error",
338→            error: classified.message,
339→            agentType: request.agentType,
340→            category: classified.category,
341→          });
342→          EventBroadcaster.emitSessionError(
343→            request.id,
344→            request.agentType,
345→            classified.message,
346→            classified.category
347→          );
348→        })
349→        .finally(() => {
350→          // Untrack when the turn completes (success, error, or cancel)
351→          untrackSession(request.id);
352→        });
353→
354→      // Dual-write: emit canonical session.started event after dispatch
355→      EventBroadcaster.emitSessionStarted(request.id, request.agentType);
356→
357→      console.log(
358→        `[TIMING][QUERY] DISPATCHED session=${request.id} dispatchTime=${Date.now() - tQueryReceived}ms`
359→      );
360→      return { accepted: true };
361→    });
362→
363→    // --- Cancel (dispatch to agent by agentType) ---
364→    EventBroadcaster.onCancel(rpcTunnel, (request) => {
365→      const agent = getAgent(request.agentType);
366→      if (agent) void agent.cancel(request.id);
367→    });
368→
369→    // --- Auth check (dispatched by agentType) ---
370→    EventBroadcaster.onClaudeAuth(rpcTunnel, (request) => {
371→      const agent = getAgent(request.agentType);
372→      if (!agent?.auth) {
373→        return Promise.reject(new Error(`Agent "${request.agentType}" does not support auth`));
374→      }
375→      return agent.auth({ id: request.id, cwd: request.options.cwd });
376→    });
377→
378→    // --- Workspace init (dispatched by agentType) ---
379→    EventBroadcaster.onWorkspaceInit(rpcTunnel, (request) => {
380→      const agent = getAgent(request.agentType);
381→      if (!agent?.initWorkspace) {
382→        return Promise.reject(
383→          new Error(`Agent "${request.agentType}" does not support workspace init`)
384→        );
385→      }
386→      return agent.initWorkspace({
387→        id: request.id,
388→        cwd: request.options.cwd,
389→        ghToken: request.options.ghToken,
390→        claudeEnvVars: request.options.claudeEnvVars,
391→      });
392→    });
393→
394→    // --- Context usage (dispatched by agentType) ---
395→    EventBroadcaster.onContextUsage(rpcTunnel, (request) => {
396→      const agent = getAgent(request.agentType);
397→      if (!agent?.getContextUsage) {
398→        return Promise.reject(
399→          new Error(`Agent "${request.agentType}" does not support context usage`)
400→        );
401→      }
402→      return agent.getContextUsage(request);
403→    });
404→
405→    // --- Permission mode updates (dispatched by agentType) ---
406→    // Fire-and-forget notification — no error if the agent doesn't support it
407→    EventBroadcaster.onUpdatePermissionMode(rpcTunnel, (request) => {
408→      const agent = getAgent(request.agentType);
409→      if (agent?.updatePermissionMode) {
410→        void agent.updatePermissionMode(request.id, request.permissionMode);
411→      }
412→    });
413→
414→    // --- Reset generator (dispatch to agent by agentType) ---
415→    EventBroadcaster.onResetGenerator(rpcTunnel, (request) => {
416→      const agent = getAgent(request.agentType);
417→      if (agent) agent.reset(request.id);
418→    });
419→  }
420→
421→  // ==========================================================================
422→  // Unix socket transport
423→  // ==========================================================================
424→
425→  /**
426→   * Handles a new TCP/Unix socket connection.
427→   * Sets up line-based JSON-RPC message framing.
428→   */
429→  private handleUnixConnection(socket: net.Socket): void {
430→    console.log("Client connected (unix)");
431→    const rpcTunnel = new RpcConnection(socket);
432→    this.setupJsonRpc(rpcTunnel);
433→
434→    let buffer = "";
435→    const decoder = new StringDecoder("utf8");
436→
437→    socket.on("data", (data) => {
438→      buffer += decoder.write(data);
439→      console.debug("Received data with length", data.length);
440→
441→      const lines = buffer.split("\n");
442→      buffer = lines.pop() || "";
443→
444→      for (const line of lines) {
445→        if (line.trim()) {
446→          rpcTunnel.handleLine(line);
447→        }
448→      }
449→    });
450→
451→    socket.on("error", (error: any) => {
452→      console.error("Socket error:", error);
453→    });
454→
455→    socket.on("close", (hadError) => {
456→      console.log(`Client disconnected (unix), hadError: ${hadError}`);
457→      rpcTunnel.stop();
458→      EventBroadcaster.detachTunnel(rpcTunnel);
459→    });
460→  }
461→
462→  // ==========================================================================
463→  // WebSocket transport
464→  // ==========================================================================
465→
466→  /**
467→   * Handles a new WebSocket connection.
468→   * Each WS text frame is a complete JSON-RPC message (no line splitting needed).
469→   */
470→  private handleWsConnection(ws: WebSocket): void {
471→    console.log("Client connected (ws)");
472→    const transport = wsTransport(ws);
473→    const rpcTunnel = new RpcConnection(transport);
474→    this.setupJsonRpc(rpcTunnel);
475→
476→    ws.on("message", (data: Buffer | string) => {
477→      const message = typeof data === "string" ? data : data.toString("utf8");
478→      console.debug("Received WS message with length", message.length);
479→      rpcTunnel.handleMessage(message);
480→    });
481→
482→    ws.on("error", (error: Error) => {
483→      console.error("WebSocket error:", error);
484→    });
485→
486→    ws.on("close", (code: number, reason: Buffer) => {
487→      console.log(`Client disconnected (ws), code=${code} reason=${reason.toString()}`);
488→      rpcTunnel.stop();
489→      EventBroadcaster.detachTunnel(rpcTunnel);
490→    });
491→  }
492→
493→  // ==========================================================================
494→  // Lifecycle
495→  // ==========================================================================
496→
497→  /**
498→   * Kills any remaining Claude child processes spawned by this sidecar.
499→   */
500→  private async killRemainingChildProcesses(): Promise<void> {
501→    return new Promise((resolve) => {
502→      const command = `/usr/bin/pgrep -P ${process.pid}`;
503→      exec(command, (error, stdout) => {
504→        if (error) {
505→          console.log("[CLEANUP] No child processes found");
506→          resolve();
507→          return;
508→        }
509→        const childPids = stdout
510→          .trim()
511→          .split("\n")
512→          .filter((pid) => pid);
513→        if (childPids.length === 0) {
514→          console.log("[CLEANUP] No child processes to kill");
515→          resolve();
516→          return;
517→        }
518→        console.log(`[CLEANUP] Found ${childPids.length} child processes: ${childPids.join(", ")}`);
519→        childPids.forEach((pid) => {
520→          try {
521→            process.kill(Number(pid), "SIGTERM");
522→            console.log(`[CLEANUP] Sent SIGTERM to child PID ${pid}`);
523→          } catch (e) {
524→            const errorMsg = getErrorMessage(e);
525→            console.log(`[CLEANUP] Failed to kill child PID ${pid}: ${errorMsg}`);
526→          }
527→        });
528→        resolve();
529→      });
530→    });
531→  }
532→
533→  private async cleanup(): Promise<void> {
534→    await this.killRemainingChildProcesses();
535→
536→    // Clean up Unix socket
537→    if (fs.existsSync(this.socketPath)) {
538→      fs.unlinkSync(this.socketPath);
539→      console.log("[CLEANUP] Removed socket file");
540→    }
541→    if (this.unixServer) {
542→      this.unixServer.close();
543→    }
544→
545→    // Clean up WebSocket server
546→    if (this.wss) {
547→      // Close all connected clients
548→      for (const client of this.wss.clients) {
549→        client.close(1001, "Server shutting down");
550→      }
551→      this.wss.close();
552→    }
553→    if (this.httpServer) {
554→      this.httpServer.close();
555→    }
556→  }
557→
558→  /**
559→   * Starts the agent-server:
560→   * 1. Clean up stale resources
561→   * 2. Initialize agent handlers
562→   * 3. Listen on the selected transport
563→   * 4. Print connection info to stdout (consumed by the Rust process manager)
564→   */
565→  async start(): Promise<void> {
566→    await this.cleanup();
567→
568→    // Register all agent handlers
569→    registerAgent(new ClaudeAgentHandler());
570→    registerAgent(new CodexAgentHandler());
571→
572→    // Initialize all registered agents
573→    console.log("Initializing agent handlers...");
574→    this.initializedAgents.clear();
575→    const initResults = initializeAllAgents();
576→    for (const [agentType, result] of initResults) {
577→      if (!result.success) {
578→        console.error(`${agentType} initialization failed:`, result.error);
579→      } else {
580→        console.log(`${agentType} handler initialized successfully`);
581→        this.initializedAgents.add(agentType);
582→      }
583→    }
584→
585→    // Mark agents as initialized for the /readyz endpoint only if at least one succeeded
586→    setAgentsInitialized(this.initializedAgents.size > 0);
587→
588→    if (this.transportMode === "ws") {
589→      return this.startWebSocket();
590→    } else {
591→      return this.startUnixSocket();
592→    }
593→  }
594→
595→  private startWebSocket(): Promise<void> {
596→    return new Promise((resolve, reject) => {
597→      // Create an HTTP server for health endpoints + WS upgrade.
598→      // Binding to 127.0.0.1 — agent-server only accepts local connections.
599→      this.httpServer = createHttpServer((req, res) => {
600→        handleHttpRequest(req, res, this.wss);
601→      });
602→
603→      this.wss = new WebSocketServer({ server: this.httpServer });
604→
605→      this.wss.on("connection", (ws) => {
606→        console.log("Server: New WebSocket connection accepted");
607→        this.handleWsConnection(ws);
608→      });
609→
610→      this.wss.on("error", (error: Error) => {
611→        console.error("WebSocketServer error:", error);
612→      });
613→
614→      // Port 0 = OS-assigned dynamic port
615→      this.httpServer.listen(0, "127.0.0.1", () => {
616→        const addr = this.httpServer!.address();
617→        const port = typeof addr === "object" && addr ? addr.port : 0;
618→
619→        console.log(`Agent-server listening on ws://127.0.0.1:${port}`);
620→        console.log(`Sidecar PID: ${process.pid}`);
621→
622→        // Machine-readable output for the Rust process manager.
623→        // LISTEN_URL is the new canonical output; SOCKET_PATH kept for transition.
624→        originalLog(`LISTEN_URL=ws://127.0.0.1:${port}`);
625→        resolve();
626→      });
627→
628→      this.httpServer.on("error", (error: Error) => {
629→        console.error("HTTP server error:", error);
630→        reject(error);
631→      });
632→    });
633→  }
634→
635→  private startUnixSocket(): Promise<void> {
636→    return new Promise((resolve, reject) => {
637→      this.unixServer = net.createServer((socket) => {
638→        console.log("Server: New connection accepted");
639→        this.handleUnixConnection(socket);
640→      });
641→
642→      this.unixServer.listen(this.socketPath, () => {
643→        console.log(`Unified sidecar listening on ${this.socketPath}`);
644→        console.log(`Sidecar PID: ${process.pid}`);
645→
646→        // Print the socket path to stdout so the OpenDevs app can connect
647→        originalLog(`SOCKET_PATH=${this.socketPath}`);
648→        resolve();
649→      });
650→
651→      this.unixServer.on("error", (error: any) => {
652→        console.error("Server error:", error);
653→        reject(error);
654→      });
655→    });
656→  }
657→}
658→
659→// ============================================================================
660→// Global error handlers
661→// ============================================================================
662→
663→process.on("uncaughtException", (error: any) => {
664→  console.error("Uncaught Exception:", error.message);
665→  if (error.stack) console.error("Stack:", error.stack);
666→  Sentry.captureException(error);
667→  Sentry.close(2000).finally(() => process.exit(1));
668→});
669→
670→process.on("unhandledRejection", (reason, _promise) => {
671→  // Sentry's built-in onUnhandledRejectionIntegration captures and normalizes
672→  // rejection reasons automatically. We only log here for local visibility.
673→  if (reason instanceof Error) {
674→    console.error("Unhandled Rejection:", reason.message);
675→    if (reason.stack) console.error("Stack:", reason.stack);
676→  }
677→  console.error("Unhandled Rejection Reason:", JSON.stringify(reason, null, 2));
678→});
679→
680→// ============================================================================
681→// Bootstrap
682→// ============================================================================
683→
684→const mode = parseTransportMode();
685→const sidecar = new UnifiedSidecar(mode);
686→sidecar.start().catch((error) => {
687→  console.error("Startup failed:", error);
688→  process.exit(1);
689→});
