  1→// sidecar/rpc-connection.ts
  2→// Bidirectional JSON-RPC 2.0 connection over a pluggable transport.
  3→//
  4→// Supports two transports:
  5→// - TCP/Unix socket (net.Socket): newline-delimited JSON lines (NDJSON)
  6→// - WebSocket (ws): each JSON-RPC message is a single WS text frame
  7→//
  8→// The caller is responsible for message framing:
  9→// - For net.Socket: split on newlines, call handleLine() per line
 10→// - For WebSocket: call handleMessage() per WS "message" event
 11→
 12→import {
 13→  JSONRPCServer,
 14→  JSONRPCClient,
 15→  JSONRPCServerAndClient,
 16→  isJSONRPCRequest,
 17→  isJSONRPCRequests,
 18→  isJSONRPCResponse,
 19→  isJSONRPCResponses,
 20→} from "json-rpc-2.0";
 21→import type { Socket } from "net";
 22→import type { WebSocket } from "ws";
 23→
 24→// ============================================================================
 25→// Transport abstraction
 26→// ============================================================================
 27→
 28→/**
 29→ * Minimal interface for sending data over a connection.
 30→ * Implemented by both net.Socket and ws.WebSocket adapters.
 31→ */
 32→export interface RpcTransport {
 33→  /** Send a string payload. For sockets, appends \n. For WS, sends as text frame. */
 34→  send(data: string): void;
 35→  /** Returns true if the underlying connection is no longer usable. */
 36→  isClosed(): boolean;
 37→}
 38→
 39→/** Wraps a net.Socket as an RpcTransport (newline-delimited JSON). */
 40→export function socketTransport(socket: Socket): RpcTransport {
 41→  return {
 42→    send(data: string) {
 43→      socket.write(data + "\n");
 44→    },
 45→    isClosed() {
 46→      return socket.destroyed;
 47→    },
 48→  };
 49→}
 50→
 51→/** Wraps a ws.WebSocket as an RpcTransport (text frames). */
 52→export function wsTransport(ws: WebSocket): RpcTransport {
 53→  return {
 54→    send(data: string) {
 55→      ws.send(data);
 56→    },
 57→    isClosed() {
 58→      // ws.readyState: 0=CONNECTING, 1=OPEN, 2=CLOSING, 3=CLOSED
 59→      return ws.readyState !== 1;
 60→    },
 61→  };
 62→}
 63→
 64→// ============================================================================
 65→// JSON parsing / validation helpers
 66→// ============================================================================
 67→
 68→function safeJsonParse(text: string): unknown | undefined {
 69→  try {
 70→    return JSON.parse(text);
 71→  } catch {
 72→    return undefined;
 73→  }
 74→}
 75→
 76→function isJsonRpcPayload(payload: unknown): boolean {
 77→  return (
 78→    isJSONRPCRequest(payload) ||
 79→    isJSONRPCRequests(payload) ||
 80→    isJSONRPCResponse(payload) ||
 81→    isJSONRPCResponses(payload)
 82→  );
 83→}
 84→
 85→// ============================================================================
 86→// RpcConnection
 87→// ============================================================================
 88→
 89→export class RpcConnection {
 90→  private transport: RpcTransport;
 91→  private peer: JSONRPCServerAndClient;
 92→
 93→  /**
 94→   * Create an RPC connection over any transport.
 95→   *
 96→   * Accepts either:
 97→   * - A net.Socket (legacy Unix socket path) — auto-wrapped in socketTransport
 98→   * - An RpcTransport (WebSocket or custom) — used directly
 99→   */
100→  constructor(transportOrSocket: RpcTransport | Socket) {
101→    // Duck-type: if it has send() and isClosed(), treat as RpcTransport.
102→    // Otherwise, wrap as a net.Socket via socketTransport().
103→    this.transport = isRpcTransport(transportOrSocket)
104→      ? transportOrSocket
105→      : socketTransport(transportOrSocket as Socket);
106→
107→    const server = new JSONRPCServer({
108→      errorListener: (message, data) => {
109→        console.error("[RpcConnection] Server error:", message, data);
110→      },
111→    });
112→
113→    const client = new JSONRPCClient((payload) => {
114→      if (this.transport.isClosed()) {
115→        return Promise.reject(new Error("Transport is closed"));
116→      }
117→      try {
118→        this.transport.send(JSON.stringify(payload));
119→        return Promise.resolve();
120→      } catch (error) {
121→        const err = error instanceof Error ? error : new Error(String(error));
122→        return Promise.reject(err);
123→      }
124→    });
125→
126→    this.peer = new JSONRPCServerAndClient(server, client, {
127→      errorListener: (message, data) => {
128→        console.error("[RpcConnection] Client error:", message, data);
129→      },
130→    });
131→  }
132→
133→  /** Register a method handler that the remote side can call */
134→  addMethod(name: string, method: (params: unknown) => Promise<unknown>): void {
135→    this.peer.addMethod(name, (params) => method(params));
136→  }
137→
138→  /** Send a one-way notification to the remote side */
139→  notify(method: string, params: unknown): void {
140→    this.peer.notify(method, params, undefined);
141→  }
142→
143→  /** Send a request to the remote side and wait for a response */
144→  request(method: string, params: unknown): Promise<unknown> {
145→    return Promise.resolve(this.peer.request(method, params, undefined));
146→  }
147→
148→  /**
149→   * Process a single line/message received from the transport.
150→   * Works for both NDJSON lines (net.Socket) and WS text frames.
151→   * Returns true if the line was a valid JSON-RPC payload.
152→   */
153→  handleLine(line: string): boolean {
154→    const t0 = Date.now();
155→    const payload = safeJsonParse(line);
156→    if (payload === undefined) {
157→      console.error("[RpcConnection] Failed to parse JSON:", line);
158→      return false;
159→    }
160→    if (!isJsonRpcPayload(payload)) {
161→      console.error("[RpcConnection] Received non-JSON-RPC payload:", payload);
162→      return false;
163→    }
164→
165→    const method = (payload as any)?.method;
166→    if (method) {
167→      console.log(
168→        `[TIMING][RpcConnection] handleLine method=${method} parseTime=${Date.now() - t0}ms lineLen=${line.length}`
169→      );
170→    }
171→
172→    void this.peer.receiveAndSend(payload, undefined, undefined).catch((e) => {
173→      console.error("[RpcConnection] Failed to handle message:", e);
174→    });
175→    return true;
176→  }
177→
178→  /** Alias for handleLine — clearer name when used with WebSocket messages. */
179→  handleMessage(message: string): boolean {
180→    return this.handleLine(message);
181→  }
182→
183→  /** Reject all pending outbound requests and tear down the connection */
184→  stop(): void {
185→    this.peer.rejectAllPendingRequests("RPC connection stopped");
186→  }
187→}
188→
189→// ============================================================================
190→// Type guard
191→// ============================================================================
192→
193→/**
194→ * Duck-type check: RpcTransport has `send` (function) and `isClosed` (function).
195→ * Anything that doesn't match is treated as a net.Socket (which has `write`).
196→ */
197→function isRpcTransport(obj: unknown): obj is RpcTransport {
198→  return (
199→    typeof obj === "object" &&
200→    obj !== null &&
201→    typeof (obj as any).send === "function" &&
202→    typeof (obj as any).isClosed === "function"
203→  );
204→}
