574→  onQuery(
575→    tunnel: RpcConnection,
576→    handler: (request: Omit<QueryRequest, "type">) => Promise<QueryAckResponse>
577→  ): void {
578→    tunnel.addMethod(SIDECAR_METHODS.QUERY, async (params) => {
579→      const parsed = QueryRequestSchema.safeParse(params);
580→      if (!parsed.success) return { accepted: false, reason: "Invalid query request" };
581→      const { type: _, ...input } = parsed.data;
582→      return handler(input);
583→    });
