658→  // ==========================================================================
659→  // Internal helpers
660→  // ==========================================================================
661→
662→  /** Generic typed RPC: send a request to the frontend with a timeout. */
663→  private async rpc<TRes>(method: string, params: unknown, timeoutMs: number): Promise<TRes> {
664→    return this.withTimeout<TRes>(
665→      this.requireTunnel().request(method, params) as Promise<TRes>,
666→      timeoutMs,
667→      method
668→    );
669→  }
670→
671→  /** Returns the first available tunnel, or throws if none are connected. */
672→  private requireTunnel(): RpcConnection {
673→    const first = this.tunnels.values().next().value;
674→    if (!first) {
675→      throw new Error("EventBroadcaster tunnel not attached.");
676→    }
677→    return first;
678→  }
679→
680→  /**
681→   * Broadcast a notification to all connected tunnels.
682→   * Dead tunnels (those that throw on notify) are automatically removed.
683→   */
684→  private broadcastNotification(method: string, params: unknown, label: string): void {
685→    const t0 = Date.now();
686→    for (const tunnel of this.tunnels) {
687→      try {
688→        tunnel.notify(method, params);
689→      } catch (err) {
690→        console.error(`[EventBroadcaster] ${label} failed, removing dead tunnel:`, err);
691→        this.tunnels.delete(tunnel);
692→      }
693→    }
694→    const elapsed = Date.now() - t0;
695→    if (elapsed > 5) {
696→      console.log(
697→        `[TIMING][EventBroadcaster] ${label} broadcast took ${elapsed}ms (${this.tunnels.size} tunnels)`
698→      );
699→    }
700→  }
701→
702→  /**
703→   * Race a tunnel request against a timeout. Rejects with a descriptive
704→   * error if the frontend does not respond within `ms` milliseconds.
705→   */
706→  private withTimeout<T>(promise: Promise<T>, ms: number, label: string): Promise<T> {
707→    let timerId: ReturnType<typeof setTimeout> | undefined;
708→
709→    const timeout = new Promise<never>((_, reject) => {
710→      timerId = setTimeout(() => {
711→        reject(
712→          new Error(
713→            `[EventBroadcaster] ${label} timed out after ${ms}ms -- frontend did not respond`
714→          )
715→        );
716→      }, ms);
717→    });
718→
719→    return Promise.race([promise, timeout]).finally(() => {
720→      if (timerId !== undefined) clearTimeout(timerId);
721→    });
722→  }
723→}
724→
725→/** Singleton instance shared across the entire sidecar process */
726→export const EventBroadcaster = new EventBroadcasterClass();
