  1→// sidecar/health.ts
  2→// Health endpoint handler and graceful shutdown coordinator for the agent-server.
  3→//
  4→// Health: GET /health returns uptime, memory, agents, connections.
  5→// Readiness: GET /readyz returns 200 if agents are initialized, 503 if not.
  6→// Graceful shutdown: drains in-flight turns before closing connections.
  7→
  8→import type { IncomingMessage, ServerResponse } from "http";
  9→import type { WebSocketServer } from "ws";
 10→import { getRegisteredAgentTypes, getAgent } from "./agents/registry";
 11→import type { AgentType } from "../shared/enums";
 12→import { EventBroadcaster } from "./event-broadcaster";
 13→
 14→// ============================================================================
 15→// Types
 16→// ============================================================================
 17→
 18→export interface HealthResponse {
 19→  status: "ok";
 20→  uptime: number;
 21→  memoryMb: number;
 22→  agents: string[];
 23→  connections: number;
 24→  version: string;
 25→  timestamp: string;
 26→}
 27→
 28→export interface ShutdownConfig {
 29→  /** Maximum time (ms) to wait for in-flight turns to drain. Default: 30_000 */
 30→  drainTimeoutMs: number;
 31→}
 32→
 33→const DEFAULT_SHUTDOWN_CONFIG: ShutdownConfig = {
 34→  drainTimeoutMs: 30_000,
 35→};
 36→
 37→// ============================================================================
 38→// Module state
 39→// ============================================================================
 40→
 41→/** Set to true once agents have been initialized */
 42→let agentsInitialized = false;
 43→
 44→/** Set to true when shutdown has been signaled */
 45→let shuttingDown = false;
 46→
 47→/** Active sessions (sessionId -> agentType). Add on turn/start, remove on idle/error/cancelled. */
 48→const activeSessions = new Map<string, string>();
 49→
 50→/** Process start time, used for uptime calculation */
 51→const startTime = Date.now();
 52→
 53→// ============================================================================
 54→// State accessors (exported for index.ts and tests)
 55→// ============================================================================
 56→
 57→export function setAgentsInitialized(value: boolean): void {
 58→  agentsInitialized = value;
 59→}
 60→
 61→export function isAgentsInitialized(): boolean {
 62→  return agentsInitialized;
 63→}
 64→
 65→export function isShuttingDown(): boolean {
 66→  return shuttingDown;
 67→}
 68→
 69→export function setShuttingDown(value: boolean): void {
 70→  shuttingDown = value;
 71→}
 72→
 73→export function getActiveSessions(): Map<string, string> {
 74→  return activeSessions;
 75→}
 76→
 77→export function trackSession(sessionId: string, agentType: string): void {
 78→  activeSessions.set(sessionId, agentType);
 79→}
 80→
 81→export function untrackSession(sessionId: string): void {
 82→  activeSessions.delete(sessionId);
 83→}
 84→
 85→export function getActiveSessionCount(): number {
 86→  return activeSessions.size;
 87→}
 88→
 89→// ============================================================================
 90→// Health endpoint handler
 91→// ============================================================================
 92→
 93→/**
 94→ * Builds the health response payload.
 95→ * Separated from the HTTP handler so it can be tested independently.
 96→ */
 97→export function buildHealthResponse(wss: WebSocketServer | null): HealthResponse {
 98→  const uptimeSeconds = (Date.now() - startTime) / 1000;
 99→  const memoryMb = Math.round((process.memoryUsage.rss() / 1024 / 1024) * 100) / 100;
100→  const agents = getRegisteredAgentTypes();
101→  const connections = wss ? wss.clients.size : 0;
102→
103→  return {
104→    status: "ok",
105→    uptime: Math.round(uptimeSeconds * 100) / 100,
106→    memoryMb,
107→    agents,
108→    connections,
109→    version: "1.0.0",
110→    timestamp: new Date().toISOString(),
111→  };
112→}
113→
114→/**
115→ * HTTP request handler for the agent-server.
116→ * Handles GET /health, GET /readyz, and returns 404 for everything else.
117→ * Non-GET requests and WebSocket upgrades are not routed here.
118→ */
119→export function handleHttpRequest(
120→  req: IncomingMessage,
121→  res: ServerResponse,
122→  wss: WebSocketServer | null
123→): void {
124→  const url = req.url || "/";
125→  const method = req.method || "GET";
126→
127→  if (method === "GET" && url === "/health") {
128→    const body = JSON.stringify(buildHealthResponse(wss));
129→    res.writeHead(200, {
130→      "Content-Type": "application/json",
131→      "Cache-Control": "no-store",
132→    });
133→    res.end(body);
134→    return;
135→  }
136→
137→  if (method === "GET" && url === "/readyz") {
138→    if (agentsInitialized && !shuttingDown) {
139→      res.writeHead(200, { "Content-Type": "application/json" });
140→      res.end(JSON.stringify({ status: "ready" }));
141→    } else {
142→      const reason = shuttingDown ? "shutting down" : "agents not initialized";
143→      res.writeHead(503, { "Content-Type": "application/json" });
144→      res.end(JSON.stringify({ status: "not ready", reason }));
145→    }
146→    return;
147→  }
148→
149→  // Everything else: 404 (WebSocket upgrades are handled separately by the WS server)
150→  res.writeHead(404, { "Content-Type": "text/plain" });
151→  res.end("Not Found");
152→}
153→
154→// ============================================================================
155→// Graceful shutdown with turn draining
156→// ============================================================================
157→
158→/**
159→ * Waits for all active sessions to complete, up to the configured timeout.
160→ * Returns true if all sessions drained, false if timeout was reached.
161→ */
162→export function waitForDrain(config: ShutdownConfig = DEFAULT_SHUTDOWN_CONFIG): Promise<boolean> {
163→  return new Promise((resolve) => {
164→    if (activeSessions.size === 0) {
165→      resolve(true);
166→      return;
167→    }
168→
169→    const deadline = Date.now() + config.drainTimeoutMs;
170→
171→    const checkInterval = setInterval(() => {
172→      if (activeSessions.size === 0) {
173→        clearInterval(checkInterval);
174→        resolve(true);
175→        return;
176→      }
177→
178→      if (Date.now() >= deadline) {
179→        clearInterval(checkInterval);
180→        resolve(false);
181→        return;
182→      }
183→    }, 100);
184→  });
185→}
186→
187→/**
188→ * Cancels all remaining active sessions using the proper cancellation flow.
189→ * Tries agent.cancel() first (which sets cancelledByUser, creates checkpoints,
190→ * and terminates subprocesses), then falls back to direct event emission.
191→ */
192→export async function cancelRemainingSessions(): Promise<void> {
193→  const entries = [...activeSessions];
194→  for (const [sessionId, agentType] of entries) {
195→    console.log(`[SHUTDOWN] Force-cancelling session ${sessionId} (agent=${agentType})`);
196→    const agent = getAgent(agentType as AgentType);
197→    if (agent) {
198→      try {
199→        await agent.cancel(sessionId);
200→      } catch (err) {
201→        console.error(
202→          `[SHUTDOWN] agent.cancel() failed for ${sessionId}, emitting events directly:`,
203→          err
204→        );
205→        EventBroadcaster.emitMessageCancelled(sessionId, agentType as any);
206→        EventBroadcaster.emitSessionCancelled(sessionId, agentType as any);
207→      }
208→    } else {
209→      EventBroadcaster.emitMessageCancelled(sessionId, agentType as any);
210→      EventBroadcaster.emitSessionCancelled(sessionId, agentType as any);
211→    }
212→  }
213→  activeSessions.clear();
214→}
215→
216→// ============================================================================
217→// Reset (for tests)
218→// ============================================================================
219→
220→export function resetHealthState(): void {
221→  agentsInitialized = false;
222→  shuttingDown = false;
223→  activeSessions.clear();
224→}
