 31→/**
 32→ * Callback to send a tool response back to the agent-server.
 33→ * Registered by server.ts after the AgentClient is created.
 34→ * Signature matches agentClient.sendTurnRespond().
 35→ */
 36→type RespondToAgentFn = (params: { sessionId: string; requestId: string; result: unknown }) => Promise<void>;
 37→
 38→let respondToAgent: RespondToAgentFn | null = null;
 39→
 40→/**
 41→ * Register the callback used to send tool relay results back to the agent-server.
 42→ * Called once at startup from server.ts.
 43→ */
 44→export function setRespondToAgent(fn: RespondToAgentFn): void {
 45→  respondToAgent = fn;
 46→}
