 51→ * Called by the AgentClient for every event notification received from the
 52→ * agent-server. Ordering guarantee: DB write completes before WS push
 53→ * so subscribers always see fresh data.
 54→ */
 55→export function handleAgentEvent(event: AgentEvent): void {
 56→  match(event)
 57→    // ── Session lifecycle ─────────────────────────────────────────────
 58→    .with({ type: "session.started" }, (e) => {
 59→      console.log(`[AgentEvent] session.started: session=${e.sessionId} agent=${e.agentType}`);
 60→      const result = persistSessionStarted(e);
 61→      if (result.ok) {
 62→        invalidate(
 63→          ["workspaces", "sessions", "session", "stats"],
 64→          { sessionIds: [e.sessionId] }
 65→        );
 66→      }
 67→    })
 68→    .with({ type: "session.idle" }, (e) => {
 69→      console.log(`[AgentEvent] session.idle: session=${e.sessionId}`);
 70→      const result = persistSessionIdle(e);
 71→      if (result.ok) {
 72→        invalidate(
 73→          ["workspaces", "sessions", "session", "stats"],
 74→          { sessionIds: [e.sessionId] }
 75→        );
 76→      }
 77→    })
 78→    .with({ type: "session.error" }, (e) => {
 79→      console.log(`[AgentEvent] session.error: session=${e.sessionId} error=${e.error}`);
 80→      const result = persistSessionError(e);
 81→      if (result.ok) {
 82→        invalidate(
 83→          ["workspaces", "sessions", "session", "stats"],
 84→          { sessionIds: [e.sessionId] }
 85→        );
 86→      }
 87→    })
 88→    .with({ type: "session.cancelled" }, (e) => {
 89→      console.log(`[AgentEvent] session.cancelled: session=${e.sessionId}`);
 90→      const result = persistSessionCancelled(e);
 91→      if (result.ok) {
 92→        invalidate(
 93→          ["workspaces", "sessions", "session", "stats"],
 94→          { sessionIds: [e.sessionId] }
 95→        );
 96→      }
 97→    })
 98→
 99→    // ── Messages ──────────────────────────────────────────────────────
100→    .with({ type: "message.assistant" }, (e) => {
101→      console.log(`[AgentEvent] message.assistant: session=${e.sessionId} msgId=${e.message.id}`);
102→      const result = persistAssistantMessage(e);
103→      if (result.ok) {
104→        invalidate(
105→          ["messages", "session"] satisfies QueryResource[],
106→          { sessionIds: [e.sessionId] }
107→        );
108→      }
109→    })
110→    .with({ type: "message.tool_result" }, (e) => {
111→      console.log(`[AgentEvent] message.tool_result: session=${e.sessionId} msgId=${e.message.id}`);
112→      const result = persistToolResultMessage(e);
113→      if (result.ok) {
114→        invalidate(
115→          ["messages", "session"] satisfies QueryResource[],
116→          { sessionIds: [e.sessionId] }
117→        );
118→      }
119→    })
120→    .with({ type: "message.result" }, (e) => {
121→      console.log(`[AgentEvent] message.result: session=${e.sessionId} subtype=${e.subtype}`);
122→      // No DB write — informational only. Session status handled by session.idle/error.
123→      persistMessageResult(e);
124→    })
125→    .with({ type: "message.cancelled" }, (e) => {
126→      console.log(`[AgentEvent] message.cancelled: session=${e.sessionId}`);
127→      const result = persistMessageCancelled(e);
128→      if (result.ok) {
129→        invalidate(
130→          ["messages", "sessions", "session", "stats"],
131→          { sessionIds: [e.sessionId] }
132→        );
133→      }
134→    })
135→
136→    // ── Interaction requests ──────────────────────────────────────────
137→    .with({ type: "request.opened" }, (e) => {
138→      console.log(`[AgentEvent] request.opened: session=${e.sessionId} requestId=${e.requestId} type=${e.requestType}`);
139→      // No DB write — relay to frontend via WS push (future: dedicated event channel)
140→    })
141→    .with({ type: "request.resolved" }, (e) => {
142→      console.log(`[AgentEvent] request.resolved: session=${e.sessionId} requestId=${e.requestId}`);
143→      // No DB write — informational
144→    })
145→
146→    // ── Tool relay ────────────────────────────────────────────────────
147→    .with({ type: "tool.request" }, (e) => {
148→      console.log(`[AgentEvent] tool.request: session=${e.sessionId} method=${e.method} requestId=${e.requestId}`);
149→      // Fire-and-forget: relay to frontend, then send response back to agent-server.
150→      // Errors are logged but don't crash the event handler.

