150→      // Errors are logged but don't crash the event handler.
151→      void relayToolRequest(e);
152→    })
153→
154→    // ── Metadata ──────────────────────────────────────────────────────
155→    .with({ type: "agent.session_id" }, (e) => {
156→      console.log(`[AgentEvent] agent.session_id: session=${e.sessionId} agentSessionId=${e.agentSessionId}`);
157→      persistAgentSessionId(e);
