164→// ---- Tool relay internal ----
165→
166→/**
167→ * Relay a tool request to the frontend and send the result back to the agent-server.
168→ *
169→ * This is async (fire-and-forget from handleAgentEvent). The relay() promise
170→ * resolves when the frontend sends q:tool_response, then we forward the result
171→ * to the agent via turn/respond.
172→ */
173→async function relayToolRequest(event: AgentEvent & { type: "tool.request" }): Promise<void> {
174→  const { sessionId, requestId, method } = event;
175→
176→  if (!respondToAgent) {
177→    console.error(`[AgentEvent] tool.request: no respondToAgent callback registered (requestId=${requestId})`);
178→    return;
179→  }
180→
181→  try {
182→    const result = await relay(event);
183→
184→    // Send the frontend's result back to the agent-server
185→    await respondToAgent({ sessionId, requestId, result });
186→    console.log(`[AgentEvent] tool.request resolved: requestId=${requestId} method=${method}`);
187→  } catch (err) {
188→    console.error(`[AgentEvent] tool.request failed: requestId=${requestId} method=${method}`, err);
189→    // Send an error result back so the agent doesn't hang waiting
190→    try {
191→      await respondToAgent({
192→        sessionId,
193→        requestId,
194→        result: { error: err instanceof Error ? err.message : "Tool relay failed" },
195→      });
196→    } catch (respondErr) {
197→      console.error(`[AgentEvent] Failed to send error response to agent: requestId=${requestId}`, respondErr);
198→    }
199→  }
200→}
