  1→// sidecar/agents/registry.ts
  2→// Agent handler interface, type definitions, and runtime registry.
  3→// Each agent type (claude, codex, etc.) implements AgentHandler and
  4→// registers itself in the registry during sidecar startup.
  5→
  6→import { getErrorMessage } from "../../shared/lib/errors";
  7→import type { AgentType, QueryRequest } from "../protocol";
  8→
  9→// ============================================================================
 10→// Type Definitions
 11→// ============================================================================
 12→
 13→/** Options passed to query(), validated by QueryRequestSchema in protocol.ts */
 14→export type QueryOptions = QueryRequest["options"];
 15→
 16→/**
 17→ * Declares which optional features an agent handler supports.
 18→ * Used for capability-based dispatch — call sites check capabilities
 19→ * instead of checking agentType strings or casting to concrete classes.
 20→ */
 21→export interface AgentCapabilities {
 22→  /** Supports auth check (e.g., Claude account info) */
 23→  auth: boolean;
 24→  /** Supports workspace initialization (slash commands, MCP servers) */
 25→  workspaceInit: boolean;
 26→  /** Supports context usage queries */
 27→  contextUsage: boolean;
 28→  /** Supports runtime permission mode changes */
 29→  permissionMode: boolean;
 30→  /** Model switching behavior: can change model mid-session, requires restart, or unsupported */
 31→  modelSwitch: "in-session" | "restart-session" | "unsupported";
 32→  /** Supports multi-turn conversations (prompt queue between turns) */
 33→  multiTurn: boolean;
 34→  /** Supports resuming from a previous session checkpoint */
 35→  sessionResume: boolean;
 36→}
 37→
 38→// ============================================================================
 39→// Optional method parameter types (provider-neutral names)
 40→// ============================================================================
 41→
 42→export interface AuthParams {
 43→  id: string;
 44→  cwd: string;
 45→}
 46→
 47→export interface InitWorkspaceParams {
 48→  id: string;
 49→  cwd: string;
 50→  ghToken?: string;
 51→  claudeEnvVars?: string;
 52→}
 53→
 54→export interface ContextUsageParams {
 55→  id: string;
 56→  options: { cwd: string; claudeSessionId: string };
 57→}
 58→
 59→/**
 60→ * Common interface for all agent handlers.
 61→ *
 62→ * Core lifecycle methods (required):
 63→ * - initialize() — one-time setup (e.g., discover executable)
 64→ * - query() — process a user prompt
 65→ * - cancel() — cancel a running session
 66→ * - reset() — tear down generator for a session
 67→ *
 68→ * Optional provider-specific methods (guarded by capabilities):
 69→ * - auth() — check account auth info
 70→ * - initWorkspace() — get slash commands + MCP server status
 71→ * - getContextUsage() — fetch context window usage
 72→ * - updatePermissionMode() — hot-swap permission mode on active query
 73→ */
 74→export interface AgentHandler {
 75→  readonly agentType: AgentType;
 76→  readonly capabilities: AgentCapabilities;
 77→
 78→  initialize(): { success: boolean; error?: string };
 79→
 80→  query(sessionId: string, prompt: string, options: QueryOptions): Promise<void>;
 81→
 82→  cancel(sessionId: string): Promise<void>;
 83→
 84→  reset(sessionId: string): void;
 85→
 86→  // Optional provider-specific methods (guarded by capabilities)
 87→  auth?(params: AuthParams): Promise<any>;
 88→  initWorkspace?(params: InitWorkspaceParams): Promise<any>;
 89→  getContextUsage?(params: ContextUsageParams): Promise<any>;
 90→  updatePermissionMode?(sessionId: string, permissionMode: string): Promise<void>;
 91→}
 92→
 93→// ============================================================================
 94→// Agent Registry
 95→// ============================================================================
 96→
 97→const registry = new Map<AgentType, AgentHandler>();
 98→
 99→/**
100→ * Registers an agent handler in the registry.
101→ * Overwrites any existing handler for the same agentType.
102→ */
103→export function registerAgent(handler: AgentHandler): void {
104→  registry.set(handler.agentType, handler);
105→}
106→
107→/**
108→ * Retrieves the agent handler for a given type.
109→ * Returns undefined if no handler is registered for that type.
110→ */
111→export function getAgent(type: AgentType): AgentHandler | undefined {
112→  return registry.get(type);
113→}
114→
115→/**
116→ * Initializes all registered agents and returns their results.
117→ * Called once during sidecar startup after all agents are registered.
118→ */
119→export function initializeAllAgents(): Map<AgentType, { success: boolean; error?: string }> {
120→  const results = new Map<AgentType, { success: boolean; error?: string }>();
121→  for (const [type, handler] of registry) {
122→    try {
123→      const result = handler.initialize();
124→      results.set(type, result);
125→    } catch (error) {
126→      results.set(type, {
127→        success: false,
128→        error: getErrorMessage(error),
129→      });
130→    }
131→  }
132→  return results;
133→}
134→
135→/**
136→ * Returns the list of registered agent type names.
137→ * Used by the health endpoint to report available agents.
138→ */
139→export function getRegisteredAgentTypes(): AgentType[] {
140→  return Array.from(registry.keys());
141→}
142→
143→/**
144→ * Clears the registry. Used in tests to reset state between runs.
145→ */
146→export function clearAgentRegistry(): void {
147→  registry.clear();
148→}
