204→    if (blockIfNotInitialized(sessionId)) return;
205→
206→    const existingQuery = claudeQueries.get(sessionId);
207→    const session = claudeSessions.get(sessionId);
208→
209→    if (isSessionActive(session) && existingQuery) {
210→      console.log(`Force-closing query for session ${sessionId}`);
211→
212→      // 1. Flag cancellation so the post-loop path persists the cancelled message
213→      session.cancelledByUser = true;
214→
215→      // 2. Create checkpoint before process dies
216→      if (session.turnId && session.cwd) {
217→        createCheckpoint(sessionId, session.turnId, "end", session.cwd, "claudeHandler");
218→      }
219→
220→      // 3. Force kill: close() terminates CLI subprocess + all children + MCP transports
221→      existingQuery.close();
222→
223→      // 4. Signal prompt generator to stop — finally block owns cleanup
224→      terminateSession(sessionId);
225→    } else {
226→      console.log(`No active session found for ${sessionId} to cancel`);
227→    }
