  1→// backend/src/services/tool-relay.ts
  2→// Manages pending tool requests being relayed from the agent-server to the frontend.
  3→//
  4→// Flow:
  5→//   Agent emits tool.request event
  6→//   → handleAgentEvent calls toolRelay.relay()
  7→//   → Backend pushes q:event { event: "tool:request", data: {...} } to all frontend WS clients
  8→//   → Frontend handles the request (browser automation, diff, terminal, plan, question)
  9→//   → Frontend sends q:tool_response { requestId, result/error } back via WS
 10→//   → Backend calls toolRelay.resolve/reject
 11→//   → relay() promise resolves → agent-event-handler sends result back to agent-server
 12→//
 13→// Timeout handling: each tool request has a timeout (set by the agent-server).
 14→// If the frontend doesn't respond within the timeout, the pending promise is rejected.
 15→
 16→import type { ToolRequestEvent } from "../../../shared/agent-events";
 17→import type { ToolRequestEventData, QServerFrame } from "../../../shared/types/query-protocol";
 18→import { broadcast } from "./ws.service";
 19→
 20→// ---- Types ----
 21→
 22→interface PendingRelay {
 23→  resolve: (result: unknown) => void;
 24→  reject: (error: Error) => void;
 25→  timer: ReturnType<typeof setTimeout>;
 26→  sessionId: string;
 27→  method: string;
 28→}
 29→
 30→// ---- Singleton State ----
 31→
 32→const pending = new Map<string, PendingRelay>();
 33→
 34→// ---- Public API ----
 35→
 36→/**
 37→ * Relay a tool request from the agent to the frontend via WebSocket.
 38→ *
 39→ * Returns a promise that resolves when the frontend sends back q:tool_response,
 40→ * or rejects if the timeout expires.
 41→ *
 42→ * The caller (agent-event-handler) uses the resolved value to send the result
 43→ * back to the agent-server via agentClient.sendTurnRespond().
 44→ */
 45→export function relay(event: ToolRequestEvent): Promise<unknown> {
 46→  const { requestId, sessionId, method, params, timeoutMs } = event;
 47→
 48→  // If there's already a pending request with this ID, reject the old one
 49→  // (shouldn't happen in practice, but prevents leaked promises)
 50→  const existing = pending.get(requestId);
 51→  if (existing) {
 52→    clearTimeout(existing.timer);
 53→    existing.reject(new Error(`Superseded by new relay for requestId=${requestId}`));
 54→    pending.delete(requestId);
 55→  }
 56→
 57→  return new Promise<unknown>((resolve, reject) => {
 58→    // Set timeout — reject if frontend doesn't respond in time
 59→    const timer = setTimeout(() => {
 60→      pending.delete(requestId);
 61→      reject(new Error(`Tool relay timed out after ${timeoutMs}ms (requestId=${requestId}, method=${method})`));
 62→    }, timeoutMs);
 63→
 64→    // Store the pending relay
 65→    pending.set(requestId, { resolve, reject, timer, sessionId, method });
 66→
 67→    // Push q:event to all connected frontend clients
 68→    const eventData: ToolRequestEventData = {
 69→      requestId,
 70→      sessionId,
 71→      method,
 72→      params,
 73→      timeoutMs,
 74→    };
 75→
 76→    const frame: QServerFrame = {
 77→      type: "q:event",
 78→      event: "tool:request",
 79→      data: eventData,
 80→    };
 81→
 82→    broadcast(JSON.stringify(frame));
 83→  });
 84→}
 85→
 86→/**
 87→ * Resolve a pending tool relay with the frontend's response.
 88→ * Called when the query engine receives a q:tool_response frame with a result.
 89→ */
 90→export function resolve(requestId: string, result: unknown): boolean {
 91→  const entry = pending.get(requestId);
 92→  if (!entry) return false;
 93→
 94→  clearTimeout(entry.timer);
 95→  pending.delete(requestId);
 96→  entry.resolve(result);
 97→  return true;
 98→}
