133→        let os = std::env::consts::OS;
134→        let arch = std::env::consts::ARCH;
135→        let is_musl = Self::detect_musl_runtime();
136→
137→        match (os, arch, is_musl) {
138→            ("linux", "x86_64", true) => Ok(Self::LinuxX64Musl),
139→            ("linux", "x86_64", false) => Ok(Self::LinuxX64),
140→            ("linux", "aarch64", _) => Ok(Self::LinuxArm64),
141→            ("macos", "aarch64", _) => Ok(Self::MacosArm64),
142→            ("macos", "x86_64", _) => Ok(Self::MacosX64),
143→            ("windows", "x86_64", _) => Ok(Self::WindowsX64),
144→            ("windows", "aarch64", _) => Ok(Self::WindowsArm64),
145→            _ => Err(AgentError::UnsupportedPlatform {
146→                os: os.to_string(),
147→                arch: arch.to_string(),
148→            }),
149→        }
150→    }
