167→            Platform::MacosArm64 => "darwin-aarch64",
168→            Platform::MacosX64 => "darwin-x86_64",
169→            Platform::WindowsX64 => "windows-x86_64",
170→            Platform::WindowsArm64 => "windows-aarch64",
171→        }
172→    }
173→}
