  3→import { assertExecutable, formatNonExecutableBinaryMessage } from "@sandbox-agent/cli-shared";
  4→
  5→export type SandboxAgentSpawnLogMode = "inherit" | "pipe" | "silent";
  6→
  7→export type SandboxAgentSpawnOptions = {
  8→  enabled?: boolean;
  9→  host?: string;
 10→  port?: number;
 11→  token?: string;
 12→  binaryPath?: string;
 13→  timeoutMs?: number;
 14→  log?: SandboxAgentSpawnLogMode;
 15→  env?: Record<string, string>;
 16→};
