 18→export type SandboxAgentSpawnHandle = {
 19→  baseUrl: string;
 20→  token: string;
 21→  child: ChildProcess;
 22→  dispose: () => Promise<void>;
 23→};
 24→
 25→const PLATFORM_PACKAGES: Record<string, string> = {
 26→  "darwin-arm64": "@sandbox-agent/cli-darwin-arm64",
 27→  "darwin-x64": "@sandbox-agent/cli-darwin-x64",
 28→  "linux-x64": "@sandbox-agent/cli-linux-x64",
 29→  "linux-arm64": "@sandbox-agent/cli-linux-arm64",
 30→  "win32-x64": "@sandbox-agent/cli-win32-x64",
 31→};
 32→
 33→const TRUST_PACKAGES =
 34→  "@sandbox-agent/cli-linux-x64 @sandbox-agent/cli-linux-arm64 @sandbox-agent/cli-darwin-arm64 @sandbox-agent/cli-darwin-x64 @sandbox-agent/cli-win32-x64";
 35→
 36→export function isNodeRuntime(): boolean {
 37→  return typeof process !== "undefined" && !!process.versions?.node;
 38→}
 39→
 40→export async function spawnSandboxAgent(options: SandboxAgentSpawnOptions, fetcher?: typeof fetch): Promise<SandboxAgentSpawnHandle> {
 41→  if (!isNodeRuntime()) {
 42→    throw new Error("Autospawn requires a Node.js runtime.");
 43→  }
 44→
 45→  const { spawn } = await import("node:child_process");
 46→  const crypto = await import("node:crypto");
 47→  const fs = await import("node:fs");
 48→  const path = await import("node:path");
 49→  const net = await import("node:net");
 50→  const { createRequire } = await import("node:module");
 51→
 52→  const bindHost = options.host ?? "127.0.0.1";
 53→  const port = options.port ?? (await getFreePort(net, bindHost));
 54→  const connectHost = bindHost === "0.0.0.0" || bindHost === "::" ? "127.0.0.1" : bindHost;
 55→  const token = options.token ?? crypto.randomBytes(24).toString("hex");
 56→  const timeoutMs = options.timeoutMs ?? 15_000;
 57→  const logMode: SandboxAgentSpawnLogMode = options.log ?? "inherit";
 58→
 59→  const binaryPath =
 60→    options.binaryPath ??
 61→    resolveBinaryFromEnv(fs, path) ??
 62→    resolveBinaryFromCliPackage(createRequire(import.meta.url), path, fs) ??
 63→    resolveBinaryFromPath(fs, path);
 64→
 65→  if (!binaryPath) {
 66→    throw new Error("sandbox-agent binary not found. Install @sandbox-agent/cli or set SANDBOX_AGENT_BIN.");
 67→  }
 68→
 69→  if (!assertExecutable(binaryPath, fs)) {
 70→    throw new Error(
 71→      formatNonExecutableBinaryMessage({
 72→        binPath: binaryPath,
 73→        trustPackages: TRUST_PACKAGES,
 74→        bunInstallBlocks: [
 75→          {
 76→            label: "Project install",
 77→            commands: [`bun pm trust ${TRUST_PACKAGES}`, "bun add sandbox-agent"],
 78→          },
 79→          {
 80→            label: "Global install",
 81→            commands: [`bun pm -g trust ${TRUST_PACKAGES}`, "bun add -g sandbox-agent"],
 82→          },
 83→        ],
 84→      }),
 85→    );
 86→  }
 87→
 88→  const stdio = logMode === "inherit" ? "inherit" : logMode === "silent" ? "ignore" : "pipe";
 89→  const args = ["server", "--host", bindHost, "--port", String(port), "--token", token];
 90→  const child = spawn(binaryPath, args, {
 91→    stdio,
 92→    env: {
 93→      ...process.env,
 94→      ...(options.env ?? {}),
 95→    },
 96→  });
 97→  const cleanup = registerProcessCleanup(child);
 98→
 99→  const baseUrl = `http://${connectHost}:${port}`;
100→  const ready = waitForHealth(baseUrl, fetcher ?? globalThis.fetch, timeoutMs, child, token);
101→
102→  await ready;
103→
104→  const dispose = async () => {
105→    if (child.exitCode !== null) {
106→      cleanup.dispose();
107→      return;
108→    }
109→    child.kill("SIGTERM");
110→    const exited = await waitForExit(child, 5_000);
111→    if (!exited) {
112→      child.kill("SIGKILL");
113→    }
114→    cleanup.dispose();
115→  };
116→
117→  return { baseUrl, token, child, dispose };
118→}
119→
120→function resolveBinaryFromEnv(fs: typeof import("node:fs"), path: typeof import("node:path")): string | null {
121→  const value = process.env.SANDBOX_AGENT_BIN;
122→  if (!value) {
123→    return null;
124→  }
125→  const resolved = path.resolve(value);
126→  if (fs.existsSync(resolved)) {
127→    return resolved;
128→  }
129→  return null;
130→}
131→
132→function resolveBinaryFromCliPackage(
133→  require: ReturnType<typeof import("node:module").createRequire>,
134→  path: typeof import("node:path"),
135→  fs: typeof import("node:fs"),
136→): string | null {
137→  const key = `${process.platform}-${process.arch}`;
138→  const pkg = PLATFORM_PACKAGES[key];
139→  if (!pkg) {
140→    return null;
141→  }
142→  try {
143→    const pkgPath = require.resolve(`${pkg}/package.json`);
144→    const bin = process.platform === "win32" ? "sandbox-agent.exe" : "sandbox-agent";
145→    const resolved = path.join(path.dirname(pkgPath), "bin", bin);
146→    return fs.existsSync(resolved) ? resolved : null;
147→  } catch {
148→    return null;
149→  }
150→}
151→
152→function resolveBinaryFromPath(fs: typeof import("node:fs"), path: typeof import("node:path")): string | null {
153→  const pathEnv = process.env.PATH ?? "";
154→  const separator = process.platform === "win32" ? ";" : ":";
155→  const candidates = pathEnv.split(separator).filter(Boolean);
156→  const bin = process.platform === "win32" ? "sandbox-agent.exe" : "sandbox-agent";
157→  for (const dir of candidates) {
158→    const resolved = path.join(dir, bin);
159→    if (fs.existsSync(resolved)) {
160→      return resolved;
161→    }
162→  }
163→  return null;
164→}
165→
166→async function getFreePort(net: typeof import("node:net"), host: string): Promise<number> {
167→  return new Promise((resolve, reject) => {
168→    const server = net.createServer();
169→    server.unref();
170→    server.on("error", reject);
171→    server.listen(0, host, () => {
172→      const address = server.address() as AddressInfo;
173→      server.close(() => resolve(address.port));
174→    });
175→  });
176→}
177→
178→async function waitForHealth(baseUrl: string, fetcher: typeof fetch | undefined, timeoutMs: number, child: ChildProcess, token: string): Promise<void> {
179→  if (!fetcher) {
180→    throw new Error("Fetch API is not available; provide a fetch implementation.");
181→  }
182→  const start = Date.now();
183→  let lastError: string | undefined;
184→
185→  while (Date.now() - start < timeoutMs) {
186→    if (child.exitCode !== null) {
187→      throw new Error("sandbox-agent exited before becoming healthy.");
188→    }
189→    try {
190→      const response = await fetcher(`${baseUrl}/v1/health`, {
191→        headers: { Authorization: `Bearer ${token}` },
192→      });
193→      if (response.ok) {
194→        return;
195→      }
196→      lastError = `status ${response.status}`;
197→    } catch (err) {
198→      lastError = err instanceof Error ? err.message : String(err);
199→    }
200→    await new Promise((resolve) => setTimeout(resolve, 200));
201→  }
202→
203→  throw new Error(`Timed out waiting for sandbox-agent health (${lastError ?? "unknown error"}).`);
204→}
205→
206→async function waitForExit(child: ChildProcess, timeoutMs: number): Promise<boolean> {
207→  if (child.exitCode !== null) {
208→    return true;
209→  }
210→  return new Promise((resolve) => {
211→    const timer = setTimeout(() => resolve(false), timeoutMs);
212→    child.once("exit", () => {
213→      clearTimeout(timer);
214→      resolve(true);
215→    });
216→  });
217→}
218→
219→function registerProcessCleanup(child: ChildProcess): { dispose: () => void } {
220→  const handler = () => {
221→    if (child.exitCode === null) {
222→      child.kill("SIGTERM");
223→    }
224→  };
225→
226→  process.once("exit", handler);
227→  process.once("SIGINT", handler);
228→  process.once("SIGTERM", handler);
229→
230→  return {
231→    dispose: () => {
232→      process.off("exit", handler);
233→      process.off("SIGINT", handler);
234→      process.off("SIGTERM", handler);
235→    },
236→  };
237→}
