150→export class InMemorySessionPersistDriver implements SessionPersistDriver {
151→  private readonly maxSessions: number;
152→  private readonly maxEventsPerSession: number;
153→  private readonly sessions = new Map<string, SessionRecord>();
154→  private readonly eventsBySession = new Map<string, SessionEvent[]>();
155→
156→  constructor(options: InMemorySessionPersistDriverOptions = {}) {
157→    this.maxSessions = normalizeCap(options.maxSessions, DEFAULT_MAX_SESSIONS);
158→    this.maxEventsPerSession = normalizeCap(options.maxEventsPerSession, DEFAULT_MAX_EVENTS_PER_SESSION);
159→  }
160→
161→  async getSession(id: string): Promise<SessionRecord | null> {
162→    const session = this.sessions.get(id);
163→    return session ? cloneSessionRecord(session) : null;
164→  }
165→
166→  async listSessions(request: ListPageRequest = {}): Promise<ListPage<SessionRecord>> {
167→    const sorted = [...this.sessions.values()].sort((a, b) => {
168→      if (a.createdAt !== b.createdAt) {
169→        return a.createdAt - b.createdAt;
170→      }
171→      return a.id.localeCompare(b.id);
172→    });
173→    const page = paginate(sorted, request);
174→    return {
175→      items: page.items.map(cloneSessionRecord),
176→      nextCursor: page.nextCursor,
177→    };
178→  }
179→
180→  async updateSession(session: SessionRecord): Promise<void> {
181→    this.sessions.set(session.id, { ...session });
182→
183→    if (!this.eventsBySession.has(session.id)) {
184→      this.eventsBySession.set(session.id, []);
185→    }
186→
187→    if (this.sessions.size <= this.maxSessions) {
188→      return;
189→    }
190→
191→    const overflow = this.sessions.size - this.maxSessions;
192→    const removable = [...this.sessions.values()]
193→      .sort((a, b) => {
194→        if (a.createdAt !== b.createdAt) {
195→          return a.createdAt - b.createdAt;
196→        }
197→        return a.id.localeCompare(b.id);
198→      })
199→      .slice(0, overflow)
200→      .map((sessionToRemove) => sessionToRemove.id);
201→
202→    for (const sessionId of removable) {
203→      this.sessions.delete(sessionId);
204→      this.eventsBySession.delete(sessionId);
205→    }
206→  }
207→
208→  async listEvents(request: ListEventsRequest): Promise<ListPage<SessionEvent>> {
209→    const all = [...(this.eventsBySession.get(request.sessionId) ?? [])].sort((a, b) => {
210→      if (a.eventIndex !== b.eventIndex) {
211→        return a.eventIndex - b.eventIndex;
212→      }
213→      return a.id.localeCompare(b.id);
214→    });
215→    const page = paginate(all, request);
216→    return {
217→      items: page.items.map(cloneSessionEvent),
218→      nextCursor: page.nextCursor,
219→    };
220→  }
221→
222→  async insertEvent(event: SessionEvent): Promise<void> {
223→    const events = this.eventsBySession.get(event.sessionId) ?? [];
224→    events.push(cloneSessionEvent(event));
225→
226→    if (events.length > this.maxEventsPerSession) {
227→      events.splice(0, events.length - this.maxEventsPerSession);
228→    }
229→
230→    this.eventsBySession.set(event.sessionId, events);
231→  }
232→}
233→
234→function cloneSessionRecord(session: SessionRecord): SessionRecord {
235→  return {
236→    ...session,
237→    sessionInit: session.sessionInit ? (JSON.parse(JSON.stringify(session.sessionInit)) as SessionRecord["sessionInit"]) : undefined,
238→    configOptions: session.configOptions ? (JSON.parse(JSON.stringify(session.configOptions)) as SessionRecord["configOptions"]) : undefined,
239→    modes: session.modes ? (JSON.parse(JSON.stringify(session.modes)) as SessionRecord["modes"]) : session.modes,
240→  };
241→}
242→
243→function cloneSessionEvent(event: SessionEvent): SessionEvent {
244→  return {
245→    ...event,
246→    payload: JSON.parse(JSON.stringify(event.payload)) as AnyMessage,
247→  };
248→}
