250→type ResponsesOf<T> = T extends { responses: infer R } ? R : never;
251→type JsonResponse<T, StatusCode extends keyof ResponsesOf<T>> = ResponsesOf<T>[StatusCode] extends {
252→  content: { "application/json": infer B };
253→}
254→  ? B
255→  : never;
256→
257→type JsonRequestBody<T> = T extends {
258→  requestBody: { content: { "application/json": infer B } };
259→}
260→  ? B
261→  : never;
262→
263→type QueryParams<T> = T extends { parameters: { query: infer Q } } ? Q : T extends { parameters: { query?: infer Q } } ? Q : never;
264→
265→function normalizeCap(value: number | undefined, fallback: number): number {
266→  if (!Number.isFinite(value) || (value ?? 0) < 1) {
267→    return fallback;
268→  }
269→  return Math.floor(value as number);
270→}
271→
272→function paginate<T>(items: T[], request: ListPageRequest): ListPage<T> {
273→  const offset = parseCursor(request.cursor);
274→  const limit = normalizeCap(request.limit, DEFAULT_LIST_LIMIT);
275→  const slice = items.slice(offset, offset + limit);
276→  const nextOffset = offset + slice.length;
277→  return {
278→    items: slice,
279→    nextCursor: nextOffset < items.length ? String(nextOffset) : undefined,
280→  };
281→}
282→
283→function parseCursor(cursor: string | undefined): number {
284→  if (!cursor) {
285→    return 0;
286→  }
287→  const parsed = Number.parseInt(cursor, 10);
288→  if (!Number.isFinite(parsed) || parsed < 0) {
289→    return 0;
290→  }
291→  return parsed;
292→}
