14→export type FsSubset = {
15→  accessSync: (path: string, mode?: number) => void;
16→  chmodSync: (path: string, mode: number) => void;
17→  constants: { X_OK: number };
18→};
19→
20→export function isBunRuntime(): boolean {
21→  if (typeof process?.versions?.bun === "string") return true;
22→  const userAgent = process?.env?.npm_config_user_agent || "";
23→  return userAgent.includes("bun/");
24→}
25→
26→const PERMISSION_ERRORS = new Set(["EACCES", "EPERM", "ENOEXEC"]);
27→
28→function isPermissionError(error: unknown): boolean {
29→  if (!error || typeof error !== "object") return false;
30→  const code = (error as { code?: unknown }).code;
31→  return typeof code === "string" && PERMISSION_ERRORS.has(code);
32→}
33→
34→/**
35→ * Checks if a binary is executable and attempts to make it executable if not.
36→ * Returns true if the binary is (or was made) executable, false if it couldn't
37→ * be made executable due to permission errors. Throws for other errors.
38→ *
39→ * Requires fs to be passed in to avoid static imports that break browser builds.
40→ */
41→export function assertExecutable(binPath: string, fs: FsSubset): boolean {
42→  if (process.platform === "win32") {
43→    return true;
44→  }
45→
46→  try {
47→    fs.accessSync(binPath, fs.constants.X_OK);
48→    return true;
49→  } catch {
50→    // Not executable, try to fix
51→  }
52→
53→  try {
54→    fs.chmodSync(binPath, 0o755);
55→    return true;
56→  } catch (error) {
57→    if (isPermissionError(error)) {
58→      return false;
59→    }
60→    throw error;
61→  }
62→}
63→
64→export function formatNonExecutableBinaryMessage(options: NonExecutableBinaryMessageOptions): string {
65→  const { binPath, trustPackages, bunInstallBlocks, genericInstallCommands, binaryName } = options;
66→
67→  const label = binaryName ?? "sandbox-agent";
68→  const lines = [`${label} binary is not executable: ${binPath}`];
69→
70→  if (isBunRuntime()) {
71→    lines.push("Allow Bun to run postinstall scripts for native binaries and reinstall:");
72→    for (const block of bunInstallBlocks) {
73→      lines.push(`${block.label}:`);
74→      for (const command of block.commands) {
75→        lines.push(`  ${command}`);
76→      }
77→    }
78→    lines.push(`Or run: chmod +x "${binPath}"`);
79→    return lines.join("\n");
80→  }
81→
82→  lines.push("Postinstall scripts for native packages did not run, so the binary was left non-executable.");
83→  if (genericInstallCommands && genericInstallCommands.length > 0) {
84→    lines.push("Reinstall with scripts enabled:");
85→    for (const command of genericInstallCommands) {
86→      lines.push(`  ${command}`);
87→    }
88→  } else {
89→    lines.push("Reinstall with scripts enabled for:");
90→    lines.push(`  ${trustPackages}`);
91→  }
92→  lines.push(`Or run: chmod +x "${binPath}"`);
93→  return lines.join("\n");
94→}
