 98→export class AcpRpcError extends Error {
 99→  readonly code: number;
100→  readonly data?: unknown;
101→
102→  constructor(code: number, message: string, data?: unknown) {
103→    const label = RPC_CODE_LABELS[code];
104→    const display = label ? `${label}: ${message}` : message;
105→    super(display);
106→    this.name = "AcpRpcError";
107→    this.code = code;
108→    this.data = data;
109→  }
110→}
