123→async function wrapRpc<T>(promise: Promise<T>): Promise<T> {
124→  try {
125→    return await promise;
126→  } catch (error) {
127→    if (isRpcErrorResponse(error)) {
128→      throw new AcpRpcError(error.code, error.message, error.data);
129→    }
130→    throw error;
131→  }
132→}
