 25→/**
 26→ * Base message entity
 27→ * Core structure for all chat messages in a session
 28→ * Matches the messages database table schema (id = UUID7, embeds created_at)
 29→ */
 30→export interface Message {
 31→  id: string;
 32→  session_id: string;
 33→  seq: number; // Per-session monotonic sequence number (auto-assigned by trigger)
 34→  role: MessageRole;
 35→  content: string; // JSON-stringified MessageContent
 36→  turn_id?: string | null; // Conversation turn identifier
 37→  sent_at?: string | null; // ISO timestamp when message sent to Claude
 38→  cancelled_at?: string | null; // ISO timestamp when user cancels message
 39→  model?: string | null; // Claude model used (e.g., 'sonnet')
