 73→/**
 74→ * Tool invocation block
 75→ * Represents a Claude Code tool being called
 76→ */
 77→export interface ToolUseBlock {
 78→  type: "tool_use";
 79→  id: string;
 80→  name: string;
 81→  input: Record<string, any>;
