  1→use std::sync::Arc;
  2→use std::time::Duration;
  3→
  4→use axum::extract::State;
  5→use axum::http::{header, HeaderMap, StatusCode};
  6→use axum::response::sse::KeepAlive;
  7→use axum::response::{IntoResponse, Response, Sse};
  8→use axum::routing::{get, post};
  9→use axum::{Json, Router};
 10→use serde::Serialize;
 11→use serde_json::{json, Value};
 12→
 13→use crate::process::{AdapterError, AdapterRuntime, PostOutcome};
 14→
 15→#[derive(Debug, Serialize)]
 16→struct HealthResponse {
 17→    ok: bool,
 18→}
 19→
 20→#[derive(Debug, Serialize)]
 21→struct Problem {
 22→    r#type: &'static str,
 23→    title: &'static str,
 24→    status: u16,
 25→    detail: String,
 26→}
 27→
 28→pub fn build_router(runtime: Arc<AdapterRuntime>) -> Router {
 29→    Router::new()
 30→        .route("/v1/health", get(get_health))
 31→        .route("/v1/rpc", post(post_rpc).get(get_rpc).delete(delete_rpc))
 32→        .with_state(runtime)
 33→}
 34→
 35→async fn get_health() -> Json<HealthResponse> {
 36→    Json(HealthResponse { ok: true })
 37→}
 38→
 39→async fn post_rpc(
 40→    State(runtime): State<Arc<AdapterRuntime>>,
 41→    headers: HeaderMap,
 42→    Json(payload): Json<Value>,
 43→) -> Response {
 44→    if !is_json_content_type(&headers) {
 45→        return problem(
 46→            StatusCode::UNSUPPORTED_MEDIA_TYPE,
 47→            "unsupported_media_type",
 48→            "content-type must be application/json",
 49→        );
 50→    }
 51→
 52→    match runtime.post(payload).await {
 53→        Ok(PostOutcome::Response(value)) => (StatusCode::OK, Json(value)).into_response(),
 54→        Ok(PostOutcome::Accepted) => StatusCode::ACCEPTED.into_response(),
 55→        Err(err) => map_error(err),
 56→    }
 57→}
 58→
 59→async fn get_rpc(
 60→    State(runtime): State<Arc<AdapterRuntime>>,
 61→    headers: HeaderMap,
 62→) -> impl IntoResponse {
 63→    let last_event_id = headers
 64→        .get("last-event-id")
 65→        .and_then(|value| value.to_str().ok())
 66→        .and_then(|value| value.parse::<u64>().ok());
 67→
 68→    let stream = runtime.clone().sse_stream(last_event_id).await;
 69→    Sse::new(stream).keep_alive(KeepAlive::new().interval(Duration::from_secs(15)))
 70→}
 71→
 72→async fn delete_rpc() -> StatusCode {
 73→    StatusCode::NO_CONTENT
 74→}
 75→
 76→fn is_json_content_type(headers: &HeaderMap) -> bool {
 77→    headers
 78→        .get(header::CONTENT_TYPE)
 79→        .and_then(|value| value.to_str().ok())
 80→        .map(|value| value.starts_with("application/json"))
 81→        .unwrap_or(false)
 82→}
 83→
 84→fn map_error(err: AdapterError) -> Response {
 85→    match err {
 86→        AdapterError::InvalidEnvelope => problem(
 87→            StatusCode::BAD_REQUEST,
 88→            "invalid_envelope",
 89→            "request body must be a JSON-RPC object",
 90→        ),
 91→        AdapterError::Timeout => problem(
 92→            StatusCode::GATEWAY_TIMEOUT,
 93→            "timeout",
 94→            "timed out waiting for agent response",
 95→        ),
 96→        AdapterError::Exited { exit_code, stderr } => {
 97→            let detail = if let Some(stderr) = stderr {
 98→                format!(
 99→                    "agent process exited before responding (exit_code: {:?}, stderr: {})",
100→                    exit_code, stderr
101→                )
102→            } else {
103→                format!(
104→                    "agent process exited before responding (exit_code: {:?})",
105→                    exit_code
106→                )
107→            };
108→            problem(StatusCode::BAD_GATEWAY, "agent_exited", &detail)
109→        }
110→        AdapterError::Write(write) => problem(
111→            StatusCode::BAD_GATEWAY,
112→            "write_failed",
113→            &format!("failed writing to agent stdin: {write}"),
114→        ),
115→        AdapterError::Serialize(ser) => problem(
116→            StatusCode::BAD_REQUEST,
117→            "serialize_failed",
118→            &format!("failed to serialize JSON payload: {ser}"),
119→        ),
120→        AdapterError::Spawn(spawn) => problem(
121→            StatusCode::BAD_GATEWAY,
122→            "spawn_failed",
123→            &format!("failed to start agent process: {spawn}"),
124→        ),
125→        AdapterError::MissingStdin | AdapterError::MissingStdout | AdapterError::MissingStderr => {
126→            problem(
127→                StatusCode::BAD_GATEWAY,
128→                "io_setup_failed",
129→                "agent subprocess pipes were not available",
130→            )
131→        }
132→    }
133→}
134→
135→fn problem(status: StatusCode, title: &'static str, detail: &str) -> Response {
136→    (
137→        status,
138→        Json(json!(Problem {
139→            r#type: "about:blank",
140→            title,
141→            status: status.as_u16(),
142→            detail: detail.to_string(),
143→        })),
144→    )
145→        .into_response()
146→}
