250→type ResponsesOf<T> = T extends { responses: infer R } ? R : never;
251→type JsonResponse<T, StatusCode extends keyof ResponsesOf<T>> = ResponsesOf<T>[StatusCode] extends {
252→  content: { "application/json": infer B };
253→}
254→  ? B
255→  : never;
256→
257→type JsonRequestBody<T> = T extends {
258→  requestBody: { content: { "application/json": infer B } };
259→}
260→  ? B
261→  : never;
262→
263→type QueryParams<T> = T extends { parameters: { query: infer Q } } ? Q : T extends { parameters: { query?: infer Q } } ? Q : never;
