272→function paginate<T>(items: T[], request: ListPageRequest): ListPage<T> {
273→  const offset = parseCursor(request.cursor);
274→  const limit = normalizeCap(request.limit, DEFAULT_LIST_LIMIT);
275→  const slice = items.slice(offset, offset + limit);
276→  const nextOffset = offset + slice.length;
277→  return {
278→    items: slice,
279→    nextCursor: nextOffset < items.length ? String(nextOffset) : undefined,
280→  };
281→}
282→
283→function parseCursor(cursor: string | undefined): number {
284→  if (!cursor) {
285→    return 0;
286→  }
287→  const parsed = Number.parseInt(cursor, 10);
288→  if (!Number.isFinite(parsed) || parsed < 0) {
289→    return 0;
290→  }
291→  return parsed;
292→}
