  1→// backend/src/services/agent-event-handler.ts
  2→// Receives canonical AgentEvent notifications from the agent-client and
  3→// dispatches them to persistence (DB writes) and WS push (query invalidation).
  4→//
  5→// This is the single entry point for all agent -> backend data flow.
  6→// Each event is handled: persist first, then invalidate (ordering matters).
  7→//
  8→// Tool relay: tool.request events are relayed to the frontend via WS.
  9→// When the frontend responds, the result is sent back to the agent-server
 10→// via the registered respondToAgent callback.
 11→
 12→import { match } from "ts-pattern";
 13→import type { AgentEvent } from "../../../shared/agent-events";
 14→import type { QueryResource } from "../../../shared/types/query-protocol";
 15→import { invalidate } from "./query-engine";
 16→import { relay } from "./tool-relay";
 17→import {
 18→  persistAssistantMessage,
 19→  persistToolResultMessage,
 20→  persistMessageResult,
 21→  persistMessageCancelled,
 22→  persistSessionStarted,
 23→  persistSessionIdle,
 24→  persistSessionError,
 25→  persistSessionCancelled,
 26→  persistAgentSessionId,
 27→} from "./agent-persistence";
 28→
 29→// ---- Tool relay callback ----
 30→
 31→/**
 32→ * Callback to send a tool response back to the agent-server.
 33→ * Registered by server.ts after the AgentClient is created.
 34→ * Signature matches agentClient.sendTurnRespond().
 35→ */
 36→type RespondToAgentFn = (params: { sessionId: string; requestId: string; result: unknown }) => Promise<void>;
 37→
 38→let respondToAgent: RespondToAgentFn | null = null;
 39→
 40→/**
 41→ * Register the callback used to send tool relay results back to the agent-server.
 42→ * Called once at startup from server.ts.
 43→ */
 44→export function setRespondToAgent(fn: RespondToAgentFn): void {
 45→  respondToAgent = fn;
 46→}
 47→
 48→/**
 49→ * Process a single canonical agent event.
 50→ *
 51→ * Called by the AgentClient for every event notification received from the
 52→ * agent-server. Ordering guarantee: DB write completes before WS push
 53→ * so subscribers always see fresh data.
 54→ */
 55→export function handleAgentEvent(event: AgentEvent): void {
 56→  match(event)
 57→    // ── Session lifecycle ─────────────────────────────────────────────
 58→    .with({ type: "session.started" }, (e) => {
 59→      console.log(`[AgentEvent] session.started: session=${e.sessionId} agent=${e.agentType}`);
 60→      const result = persistSessionStarted(e);
 61→      if (result.ok) {
 62→        invalidate(
 63→          ["workspaces", "sessions", "session", "stats"],
 64→          { sessionIds: [e.sessionId] }
 65→        );
 66→      }
 67→    })
 68→    .with({ type: "session.idle" }, (e) => {
 69→      console.log(`[AgentEvent] session.idle: session=${e.sessionId}`);
 70→      const result = persistSessionIdle(e);
 71→      if (result.ok) {
 72→        invalidate(
 73→          ["workspaces", "sessions", "session", "stats"],
 74→          { sessionIds: [e.sessionId] }
 75→        );
 76→      }
 77→    })
 78→    .with({ type: "session.error" }, (e) => {
 79→      console.log(`[AgentEvent] session.error: session=${e.sessionId} error=${e.error}`);
 80→      const result = persistSessionError(e);
 81→      if (result.ok) {
 82→        invalidate(
 83→          ["workspaces", "sessions", "session", "stats"],
 84→          { sessionIds: [e.sessionId] }
 85→        );
 86→      }
 87→    })
 88→    .with({ type: "session.cancelled" }, (e) => {
 89→      console.log(`[AgentEvent] session.cancelled: session=${e.sessionId}`);
 90→      const result = persistSessionCancelled(e);
 91→      if (result.ok) {
 92→        invalidate(
 93→          ["workspaces", "sessions", "session", "stats"],
 94→          { sessionIds: [e.sessionId] }
 95→        );
 96→      }
 97→    })
 98→
 99→    // ── Messages ──────────────────────────────────────────────────────
100→    .with({ type: "message.assistant" }, (e) => {
101→      console.log(`[AgentEvent] message.assistant: session=${e.sessionId} msgId=${e.message.id}`);
102→      const result = persistAssistantMessage(e);
103→      if (result.ok) {
104→        invalidate(
105→          ["messages", "session"] satisfies QueryResource[],
106→          { sessionIds: [e.sessionId] }
107→        );
108→      }
109→    })
110→    .with({ type: "message.tool_result" }, (e) => {
111→      console.log(`[AgentEvent] message.tool_result: session=${e.sessionId} msgId=${e.message.id}`);
112→      const result = persistToolResultMessage(e);
113→      if (result.ok) {
114→        invalidate(
115→          ["messages", "session"] satisfies QueryResource[],
116→          { sessionIds: [e.sessionId] }
117→        );
118→      }
119→    })
120→    .with({ type: "message.result" }, (e) => {
121→      console.log(`[AgentEvent] message.result: session=${e.sessionId} subtype=${e.subtype}`);
122→      // No DB write — informational only. Session status handled by session.idle/error.
123→      persistMessageResult(e);
124→    })
125→    .with({ type: "message.cancelled" }, (e) => {
126→      console.log(`[AgentEvent] message.cancelled: session=${e.sessionId}`);
127→      const result = persistMessageCancelled(e);
128→      if (result.ok) {
129→        invalidate(
130→          ["messages", "sessions", "session", "stats"],
131→          { sessionIds: [e.sessionId] }
132→        );
133→      }
134→    })
135→
136→    // ── Interaction requests ──────────────────────────────────────────
137→    .with({ type: "request.opened" }, (e) => {
138→      console.log(`[AgentEvent] request.opened: session=${e.sessionId} requestId=${e.requestId} type=${e.requestType}`);
139→      // No DB write — relay to frontend via WS push (future: dedicated event channel)
140→    })
141→    .with({ type: "request.resolved" }, (e) => {
142→      console.log(`[AgentEvent] request.resolved: session=${e.sessionId} requestId=${e.requestId}`);
143→      // No DB write — informational
144→    })
145→
146→    // ── Tool relay ────────────────────────────────────────────────────
147→    .with({ type: "tool.request" }, (e) => {
148→      console.log(`[AgentEvent] tool.request: session=${e.sessionId} method=${e.method} requestId=${e.requestId}`);
149→      // Fire-and-forget: relay to frontend, then send response back to agent-server.
150→      // Errors are logged but don't crash the event handler.
151→      void relayToolRequest(e);
152→    })
153→
154→    // ── Metadata ──────────────────────────────────────────────────────
155→    .with({ type: "agent.session_id" }, (e) => {
156→      console.log(`[AgentEvent] agent.session_id: session=${e.sessionId} agentSessionId=${e.agentSessionId}`);
157→      persistAgentSessionId(e);
158→      // No invalidation needed — agent_session_id is not exposed in any query
159→    })
160→
161→    .exhaustive();
162→}
163→
164→// ---- Tool relay internal ----
165→
166→/**
167→ * Relay a tool request to the frontend and send the result back to the agent-server.
168→ *
169→ * This is async (fire-and-forget from handleAgentEvent). The relay() promise
170→ * resolves when the frontend sends q:tool_response, then we forward the result
171→ * to the agent via turn/respond.
172→ */
173→async function relayToolRequest(event: AgentEvent & { type: "tool.request" }): Promise<void> {
174→  const { sessionId, requestId, method } = event;
175→
176→  if (!respondToAgent) {
177→    console.error(`[AgentEvent] tool.request: no respondToAgent callback registered (requestId=${requestId})`);
178→    return;
179→  }
180→
181→  try {
182→    const result = await relay(event);
183→
184→    // Send the frontend's result back to the agent-server
185→    await respondToAgent({ sessionId, requestId, result });
186→    console.log(`[AgentEvent] tool.request resolved: requestId=${requestId} method=${method}`);
187→  } catch (err) {
188→    console.error(`[AgentEvent] tool.request failed: requestId=${requestId} method=${method}`, err);
189→    // Send an error result back so the agent doesn't hang waiting
190→    try {
191→      await respondToAgent({
192→        sessionId,
193→        requestId,
194→        result: { error: err instanceof Error ? err.message : "Tool relay failed" },
195→      });
196→    } catch (respondErr) {
197→      console.error(`[AgentEvent] Failed to send error response to agent: requestId=${requestId}`, respondErr);
198→    }
199→  }
200→}
