 1→/**
 2→ * Parse message content from the database into typed content blocks.
 3→ *
 4→ * The DB stores content in exactly 3 formats:
 5→ *   1. Plain text string (user messages from backend POST)
 6→ *   2. JSON.stringify(ContentBlock[]) — assistant messages, tool results
 7→ *   3. JSON.stringify({ message: { stop_reason }, blocks: ContentBlock[] }) — cancelled envelope
 8→ *
 9→ * Legacy rows may have envelope format for any stop_reason (not just "cancelled").
10→ */
11→
12→import type { ContentBlock } from "../types";
13→
14→/**
15→ * Parse a raw `content` column value into typed content blocks.
16→ *
17→ * Returns ContentBlock[] for JSON array or envelope formats,
18→ * wraps plain text in [{ type: "text", text }] on parse failure.
19→ */
20→export function parseContentBlocks(content: string): (ContentBlock | string)[] | string {
21→  try {
22→    const parsed = JSON.parse(content);
23→
24→    // Format 2: ContentBlock[] (most common — assistant messages, tool results)
25→    if (Array.isArray(parsed)) {
26→      return parsed as (ContentBlock | string)[];
27→    }
28→
29→    // Format 3: Envelope — { message: { stop_reason }, blocks: [...] }
30→    // Written for cancelled messages; legacy rows may have other stop_reasons.
31→    if (
32→      parsed !== null &&
33→      typeof parsed === "object" &&
34→      "message" in parsed &&
35→      "blocks" in parsed &&
36→      Array.isArray(parsed.blocks)
37→    ) {
38→      return parsed.blocks as (ContentBlock | string)[];
39→    }
40→
41→    // JSON-encoded string (e.g. JSON.stringify("hello") → '"hello"')
42→    if (typeof parsed === "string") {
43→      return parsed;
44→    }
45→
46→    // Unexpected shape — wrap as text so it renders safely
47→    return [{ type: "text" as const, text: JSON.stringify(parsed) }];
48→  } catch {
49→    // Format 1: Plain text (not valid JSON) — wrap in TextBlock
50→    return [{ type: "text" as const, text: content }];
51→  }
52→}
53→
54→/**
55→ * Check if a raw message content string represents a cancelled response.
56→ *
57→ * The sidecar writes cancelled messages with envelope:
58→ *   { message: { stop_reason: "cancelled" }, blocks: [...] }
59→ */
60→export function isCancelledMessage(content: string): boolean {
61→  try {
62→    const parsed = JSON.parse(content);
63→    return (
64→      parsed !== null &&
65→      typeof parsed === "object" &&
66→      !Array.isArray(parsed) &&
67→      Array.isArray(parsed.blocks) &&
68→      parsed.message?.stop_reason === "cancelled"
69→    );
70→  } catch {
71→    return false;
72→  }
73→}
