 1→/**
 2→ * Block Renderer
 3→ *
 4→ * Smart dispatcher that renders different content block types.
 5→ * Handles text, tool_use, tool_result, and thinking blocks.
 6→ *
 7→ * CRITICAL: Links tool_use blocks with their corresponding tool_result blocks
 8→ * using the toolResultMap. tool_result blocks are NOT rendered standalone -
 9→ * they're only displayed as part of their tool_use block.
10→ */
11→
12→import { memo } from "react";
13→import { match } from "ts-pattern";
14→import type { ContentBlock, MessageRole } from "@/shared/types";
15→import { cn } from "@/shared/lib/utils";
16→import { TextBlock } from "./TextBlock";
17→import { ToolUseBlock } from "./ToolUseBlock";
18→import { ThinkingBlock } from "./ThinkingBlock";
19→import { useSession } from "../../context";
20→
21→interface BlockRendererProps {
22→  block: ContentBlock | string;
23→  index: number;
24→  role?: MessageRole;
25→  isStreaming?: boolean; // true only for the text block currently being generated
26→}
27→
28→/**
29→ * Memoized: block is a parsed JSON object (stable ref), index/role/isStreaming
30→ * are primitives. Prevents re-renders of sibling blocks when new content streams in.
31→ */
32→export const BlockRenderer = memo(function BlockRenderer({
33→  block,
34→  index,
35→  role,
36→  isStreaming,
37→}: BlockRendererProps) {
38→  const { toolResultMap } = useSession();
39→  // Handle null/undefined blocks gracefully
40→  if (!block) {
41→    if (import.meta.env.DEV) {
42→      console.warn("[BlockRenderer] Received null/undefined block at index:", index);
43→    }
44→    return null;
45→  }
46→
47→  // Streaming text = muted (60% opacity). Everything else = normal (full opacity).
48→  const weight = isStreaming ? "muted" : "normal";
49→
50→  // Handle string blocks (convert to text block)
51→  if (typeof block === "string") {
52→    return <TextBlock block={{ type: "text", text: block }} role={role} weight={weight} />;
53→  }
54→
55→  // Dispatch based on block type
56→  return match(block)
57→    .with({ type: "text" }, (b) => <TextBlock block={b} role={role} weight={weight} />)
58→    .with({ type: "image" }, (b) => {
59→      // Display-only image in chat (no remove button)
60→      // User: compact 80×80 thumbnails; Assistant: larger inline display
61→      const isUser = role === "user";
62→      return (
63→        <div
64→          className={cn(
65→            "border-border/60 overflow-hidden rounded-lg border",
66→            isUser && "h-[80px] w-[80px] shrink-0"
67→          )}
68→        >
69→          <img
70→            src={`data:${b.source.media_type};base64,${b.source.data}`}
71→            alt="Pasted image"
72→            className={isUser ? "h-full w-full object-cover" : "max-h-64 max-w-full object-contain"}
73→          />
74→        </div>
75→      );
76→    })
77→    .with({ type: "tool_use" }, (b) => (
78→      <ToolUseBlock block={b} toolResult={toolResultMap.get(b.id)} />
79→    ))
80→    .with({ type: "tool_result" }, () => null)
81→    .with({ type: "thinking" }, (b) => <ThinkingBlock block={b} />)
82→    .otherwise((b) => {
83→      if (import.meta.env.DEV) {
84→        console.warn("[BlockRenderer] Unknown block type:", (b as { type?: string }).type, b);
85→      }
86→      return null;
87→    });
88→});
