 27→    if (!existsSync(rpcTypesPath)) {
 28→      throw new Error(`rpc-types.ts not found at ${rpcTypesPath}`);
 29→    }
 30→
 31→    const tsconfig = resolveTsconfig(repoRoot);
 32→    const definitions = generateDefinitions(rpcTypesPath, tsconfig);
 33→    if (Object.keys(definitions).length === 0) {
 34→      console.log("  [warn] No schemas extracted from source, using fallback");
 35→      return createFallbackSchema();
 36→    }
 37→
 38→    console.log(`  [ok] Extracted ${Object.keys(definitions).length} types from source`);
 39→    return createNormalizedSchema("pi", "Pi RPC Schema", definitions);
 40→  } catch (error) {
 41→    const errorMessage = error instanceof Error ? error.message : String(error);
 42→    console.log(`  [warn] Pi schema extraction failed: ${errorMessage}`);
 43→    console.log("  [fallback] Using embedded schema definitions");
