 50→async function downloadToFile(url: string, filePath: string): Promise<void> {
 51→  const response = await fetch(url);
 52→  if (!response.ok) {
 53→    throw new Error(`HTTP ${response.status}: ${response.statusText}`);
 54→  }
 55→  const buffer = Buffer.from(await response.arrayBuffer());
 56→  writeFileSync(filePath, buffer);
 57→}
