 59→function findRepoRoot(root: string): string {
 60→  const entries = readdirSync(root, { withFileTypes: true }).filter((entry) => entry.isDirectory());
 61→  const repoDir = entries.find((entry) => entry.name.startsWith("pi-mono"));
 62→  if (!repoDir) {
 63→    throw new Error("pi-mono source directory not found after extraction");
 64→  }
 65→  return join(root, repoDir.name);
 66→}
