 68→function resolveTsconfig(root: string): string | undefined {
 69→  const candidates = [join(root, "tsconfig.json"), join(root, "tsconfig.base.json"), join(root, "packages", "coding-agent", "tsconfig.json")];
 70→  return candidates.find((path) => existsSync(path));
 71→}
