 73→function generateDefinitions(rpcTypesPath: string, tsconfigPath?: string): Record<string, JSONSchema7> {
 74→  const definitions: Record<string, JSONSchema7> = {};
 75→
 76→  for (const typeName of TARGET_TYPES) {
 77→    const config: Config = {
 78→      path: rpcTypesPath,
 79→      type: typeName,
 80→      expose: "all",
 81→      skipTypeCheck: false,
 82→      topRef: false,
 83→      ...(tsconfigPath ? { tsconfig: tsconfigPath } : {}),
 84→    };
 85→    const schema = createGenerator(config).createSchema(typeName) as JSONSchema7;
 86→    mergeDefinitions(definitions, schema, typeName);
 87→  }
 88→
 89→  return definitions;
 90→}
