 92→function mergeDefinitions(target: Record<string, JSONSchema7>, schema: JSONSchema7, typeName: string): void {
 93→  if (schema.definitions) {
 94→    for (const [name, def] of Object.entries(schema.definitions)) {
 95→      target[name] = def as JSONSchema7;
 96→    }
 97→  } else if (schema.$defs) {
 98→    for (const [name, def] of Object.entries(schema.$defs)) {
 99→      target[name] = def as JSONSchema7;
100→    }
101→  } else {
102→    target[typeName] = schema;
103→  }
104→
105→  if (!target[typeName]) {
106→    target[typeName] = schema;
107→  }
108→}
