 88→const RPC_CODE_LABELS: Record<number, string> = {
 89→  [-32700]: "Parse error",
 90→  [-32600]: "Invalid request",
 91→  [-32601]: "Method not supported by agent",
 92→  [-32602]: "Invalid parameters",
 93→  [-32603]: "Internal agent error",
 94→  [-32000]: "Authentication required",
 95→  [-32002]: "Resource not found",
