 98→export class AcpRpcError extends Error {
 99→  readonly code: number;
100→  readonly data?: unknown;
101→
102→  constructor(code: number, message: string, data?: unknown) {
103→    const label = RPC_CODE_LABELS[code];
104→    const display = label ? `${label}: ${message}` : message;
105→    super(display);
106→    this.name = "AcpRpcError";
107→    this.code = code;
108→    this.data = data;
109→  }
110→}
111→
112→function isRpcErrorResponse(value: unknown): value is RpcErrorResponse {
113→  return (
114→    typeof value === "object" &&
115→    value !== null &&
116→    "code" in value &&
117→    typeof (value as RpcErrorResponse).code === "number" &&
118→    "message" in value &&
119→    typeof (value as RpcErrorResponse).message === "string"
120→  );
121→}
