252→class StreamableHttpAcpTransport {
253→  readonly stream: Stream;
254→
255→  private readonly baseUrl: string;
256→  private readonly path: string;
257→  private readonly fetcher: typeof fetch;
258→  private readonly token?: string;
259→  private readonly defaultHeaders?: HeadersInit;
260→  private readonly onEnvelope?: AcpEnvelopeObserver;
261→  private readonly bootstrapQuery: URLSearchParams | null;
262→
263→  private readableController: ReadableStreamDefaultController<AnyMessage> | null = null;
264→  private sseAbortController: AbortController | null = null;
265→  private sseLoop: Promise<void> | null = null;
266→  private lastEventId: string | null = null;
267→  private closed = false;
268→  private closingPromise: Promise<void> | null = null;
269→  private postedOnce = false;
270→  private readonly seenResponseIds = new Set<string>();
271→  private readonly seenResponseIdOrder: string[] = [];
272→
273→  constructor(options: StreamableHttpAcpTransportOptions) {
274→    this.baseUrl = options.baseUrl.replace(/\/$/, "");
275→    this.path = normalizePath(options.transport?.path ?? DEFAULT_ACP_PATH);
276→    this.fetcher = options.fetcher;
277→    this.token = options.token;
278→    this.defaultHeaders = options.defaultHeaders;
279→    this.onEnvelope = options.onEnvelope;
280→    this.bootstrapQuery = options.transport?.bootstrapQuery ? buildQueryParams(options.transport.bootstrapQuery) : null;
281→
282→    this.stream = {
283→      readable: new ReadableStream<AnyMessage>({
284→        start: (controller) => {
285→          this.readableController = controller;
286→        },
287→        cancel: async () => {
288→          await this.close();
289→        },
290→      }),
291→      writable: new WritableStream<AnyMessage>({
292→        write: async (message) => {
293→          await this.writeMessage(message);
294→        },
295→        close: async () => {
296→          await this.close();
297→        },
298→        abort: async () => {
299→          await this.close();
300→        },
301→      }),
302→    };
303→  }
304→
305→  async close(): Promise<void> {
306→    if (this.closingPromise) {
307→      return this.closingPromise;
308→    }
309→
310→    this.closingPromise = this.closeImpl();
311→    return this.closingPromise;
312→  }
313→
314→  private async closeImpl(): Promise<void> {
315→    if (this.closed) {
316→      return;
317→    }
318→
319→    this.closed = true;
320→
321→    if (this.sseAbortController) {
322→      this.sseAbortController.abort();
323→    }
324→
325→    if (!this.postedOnce) {
326→      try {
327→        this.readableController?.close();
328→      } catch {
329→        // no-op
330→      }
331→      this.readableController = null;
332→      return;
333→    }
334→
335→    const deleteHeaders = this.buildHeaders({
336→      Accept: "application/json",
337→    });
338→
339→    try {
340→      const response = await this.fetcher(this.buildUrl(), {
341→        method: "DELETE",
342→        headers: deleteHeaders,
343→        signal: timeoutSignal(2_000),
344→      });
345→
346→      if (!response.ok && response.status !== 404) {
347→        throw new AcpHttpError(response.status, await readProblem(response), response);
348→      }
349→    } catch {
350→      // Ignore close errors; close must be best effort.
351→    }
352→
353→    try {
354→      this.readableController?.close();
355→    } catch {
356→      // no-op
357→    }
358→
359→    this.readableController = null;
360→  }
361→
362→  private async writeMessage(message: AnyMessage): Promise<void> {
363→    if (this.closed) {
364→      throw new Error("ACP client is closed");
365→    }
366→
367→    this.observeEnvelope(message, "outbound");
368→
369→    const headers = this.buildHeaders({
370→      "Content-Type": "application/json",
371→      Accept: "application/json",
372→    });
373→
374→    const url = this.buildUrl(this.bootstrapQueryIfNeeded());
375→    this.postedOnce = true;
376→    this.ensureSseLoop();
377→    void this.postMessage(url, headers, message);
378→  }
379→
380→  private async postMessage(url: string, headers: Headers, message: AnyMessage): Promise<void> {
381→    try {
382→      const response = await this.fetcher(url, {
383→        method: "POST",
384→        headers,
385→        body: JSON.stringify(message),
386→      });
387→
388→      if (!response.ok) {
389→        throw new AcpHttpError(response.status, await readProblem(response), response);
390→      }
391→
392→      if (response.status === 200) {
393→        const text = await response.text();
394→        if (text.trim()) {
395→          const envelope = JSON.parse(text) as AnyMessage;
396→          this.pushInbound(envelope);
397→        }
398→        return;
399→      }
400→
401→      // Drain response body so the underlying connection is released back to
402→      // the pool. Without this, Node.js undici keeps the socket occupied and
403→      // may stall subsequent requests to the same origin.
404→      await response.text().catch(() => {});
405→    } catch (error) {
406→      console.error("ACP write error:", error);
407→      this.failReadable(error);
408→    }
409→  }
410→
411→  private ensureSseLoop(): void {
412→    if (this.sseLoop || this.closed || !this.postedOnce) {
413→      return;
414→    }
415→
416→    this.sseLoop = this.runSseLoop().finally(() => {
417→      this.sseLoop = null;
418→    });
419→  }
420→
421→  private async runSseLoop(): Promise<void> {
422→    while (!this.closed) {
423→      this.sseAbortController = new AbortController();
424→
425→      const headers = this.buildHeaders({
426→        Accept: "text/event-stream",
427→      });
428→
429→      if (this.lastEventId) {
430→        headers.set("Last-Event-ID", this.lastEventId);
431→      }
432→
433→      try {
434→        const response = await this.fetcher(this.buildUrl(), {
435→          method: "GET",
436→          headers,
437→          signal: this.sseAbortController.signal,
438→        });
439→        if (!response.ok) {
440→          throw new AcpHttpError(response.status, await readProblem(response), response);
441→        }
442→
443→        if (!response.body) {
444→          throw new Error("SSE stream is not readable in this environment.");
445→        }
446→
447→        await this.consumeSse(response.body);
448→
449→        if (!this.closed) {
450→          await delay(150);
451→        }
452→      } catch (error) {
453→        if (this.closed || isAbortError(error)) {
454→          return;
455→        }
456→
457→        // SSE failure is non-fatal: the POST request/response flow still works.
458→        // Exiting the loop allows ensureSseLoop() to restart it on the next POST.
459→        return;
460→      }
461→    }
462→  }
463→
464→  private async consumeSse(body: ReadableStream<Uint8Array>): Promise<void> {
465→    const reader = body.getReader();
466→    const decoder = new TextDecoder();
467→    let buffer = "";
468→
469→    try {
470→      while (!this.closed) {
471→        const { done, value } = await reader.read();
472→        if (done) {
473→          return;
474→        }
475→
476→        buffer += decoder.decode(value, { stream: true }).replace(/\r\n/g, "\n");
477→
478→        let separatorIndex = buffer.indexOf("\n\n");
479→        while (separatorIndex !== -1) {
480→          const eventChunk = buffer.slice(0, separatorIndex);
481→          buffer = buffer.slice(separatorIndex + 2);
482→          this.processSseEvent(eventChunk);
483→          separatorIndex = buffer.indexOf("\n\n");
484→        }
485→      }
486→    } finally {
487→      reader.releaseLock();
488→    }
489→  }
490→
491→  private processSseEvent(chunk: string): void {
492→    if (!chunk.trim()) {
493→      return;
494→    }
495→
496→    let eventName = "message";
497→    let eventId: string | null = null;
498→    const dataLines: string[] = [];
499→
500→    for (const line of chunk.split("\n")) {
501→      if (!line || line.startsWith(":")) {
502→        continue;
503→      }
504→
505→      if (line.startsWith("event:")) {
506→        eventName = line.slice(6).trim();
507→        continue;
508→      }
509→
510→      if (line.startsWith("id:")) {
511→        eventId = line.slice(3).trim();
512→        continue;
513→      }
514→
515→      if (line.startsWith("data:")) {
516→        dataLines.push(line.slice(5).trimStart());
517→      }
518→    }
519→
520→    if (eventId) {
521→      this.lastEventId = eventId;
522→    }
523→
524→    if (eventName !== "message" || dataLines.length === 0) {
525→      return;
526→    }
527→
528→    const payloadText = dataLines.join("\n");
529→    if (!payloadText.trim()) {
530→      return;
531→    }
532→
533→    const envelope = JSON.parse(payloadText) as AnyMessage;
534→    this.pushInbound(envelope);
535→  }
536→
537→  private pushInbound(envelope: AnyMessage): void {
538→    if (this.closed) {
539→      return;
540→    }
541→
542→    const responseId = responseEnvelopeId(envelope);
543→    if (responseId) {
544→      if (this.seenResponseIds.has(responseId)) {
545→        return;
546→      }
547→      this.seenResponseIds.add(responseId);
548→      this.seenResponseIdOrder.push(responseId);
549→      if (this.seenResponseIdOrder.length > 2048) {
550→        const oldest = this.seenResponseIdOrder.shift();
551→        if (oldest) {
552→          this.seenResponseIds.delete(oldest);
553→        }
554→      }
555→    }
556→
557→    this.observeEnvelope(envelope, "inbound");
558→
559→    try {
560→      this.readableController?.enqueue(envelope);
561→    } catch (error) {
562→      this.failReadable(error);
563→    }
564→  }
565→
566→  private failReadable(error: unknown): void {
567→    if (this.closed) {
568→      return;
569→    }
570→
571→    this.closed = true;
572→
573→    try {
574→      this.readableController?.error(error);
575→    } catch {
576→      // no-op
577→    }
578→
579→    this.readableController = null;
580→
581→    if (this.sseAbortController) {
582→      this.sseAbortController.abort();
583→    }
584→  }
585→
586→  private observeEnvelope(message: AnyMessage, direction: AcpEnvelopeDirection): void {
587→    if (!this.onEnvelope) {
588→      return;
589→    }
590→
591→    this.onEnvelope(message, direction);
592→  }
593→
594→  private buildHeaders(extra?: HeadersInit): Headers {
595→    const headers = new Headers(this.defaultHeaders ?? undefined);
596→
597→    if (this.token) {
598→      headers.set("Authorization", `Bearer ${this.token}`);
599→    }
600→
601→    if (extra) {
602→      const merged = new Headers(extra);
603→      merged.forEach((value, key) => headers.set(key, value));
604→    }
605→
606→    return headers;
607→  }
608→
609→  private buildUrl(query?: URLSearchParams | null): string {
610→    const url = new URL(`${this.baseUrl}${this.path}`);
611→    if (query) {
612→      for (const [key, value] of query.entries()) {
613→        url.searchParams.set(key, value);
614→      }
615→    }
616→    return url.toString();
617→  }
618→
619→  private bootstrapQueryIfNeeded(): URLSearchParams | null {
620→    if (this.postedOnce || !this.bootstrapQuery || this.bootstrapQuery.size === 0) {
621→      return null;
622→    }
623→    return this.bootstrapQuery;
624→  }
625→}
626→
627→function buildClientHandlers(client?: Partial<Client>): Client {
628→  const fallbackPermission: RequestPermissionResponse = {
629→    outcome: {
630→      outcome: "cancelled",
631→    } as RequestPermissionOutcome,
632→  };
633→
634→  return {
635→    requestPermission: async (request: RequestPermissionRequest) => {
636→      if (client?.requestPermission) {
637→        return client.requestPermission(request);
638→      }
639→      return fallbackPermission;
640→    },
641→    sessionUpdate: async (notification: SessionNotification) => {
642→      if (client?.sessionUpdate) {
643→        await client.sessionUpdate(notification);
644→      }
645→    },
646→    readTextFile: client?.readTextFile,
647→    writeTextFile: client?.writeTextFile,
648→    createTerminal: client?.createTerminal,
649→    terminalOutput: client?.terminalOutput,
650→    releaseTerminal: client?.releaseTerminal,
651→    waitForTerminalExit: client?.waitForTerminalExit,
652→    killTerminal: client?.killTerminal,
653→    extMethod: client?.extMethod,
654→    extNotification: async (method: string, params: Record<string, unknown>) => {
655→      if (client?.extNotification) {
656→        await client.extNotification(method, params);
657→      }
658→    },
659→  };
660→}
