662→function responseEnvelopeId(message: AnyMessage): string | null {
663→  if (typeof message !== "object" || message === null) {
664→    return null;
665→  }
666→  const record = message as Record<string, unknown>;
667→  if ("method" in record) {
668→    return null;
669→  }
670→  if (!("result" in record) && !("error" in record)) {
671→    return null;
672→  }
673→  const id = record.id;
674→  if (id === null || id === undefined) {
675→    return null;
676→  }
677→  return String(id);
678→}
