692→function isAbortError(error: unknown): boolean {
693→  return error instanceof DOMException && error.name === "AbortError";
694→}
695→
696→function delay(ms: number): Promise<void> {
697→  return new Promise((resolve) => setTimeout(resolve, ms));
698→}
699→
700→function timeoutSignal(timeoutMs: number): AbortSignal | undefined {
701→  if (typeof AbortSignal !== "undefined" && typeof AbortSignal.timeout === "function") {
702→    return AbortSignal.timeout(timeoutMs);
703→  }
704→  return undefined;
705→}
706→
707→function normalizePath(path: string): string {
708→  if (!path.startsWith("/")) {
709→    return `/${path}`;
710→  }
711→  return path;
712→}
713→
714→function buildQueryParams(source: Record<string, QueryValue>): URLSearchParams {
715→  const params = new URLSearchParams();
716→  for (const [key, value] of Object.entries(source)) {
717→    if (value === undefined || value === null) {
718→      continue;
719→    }
720→    params.set(key, String(value));
721→  }
722→  return params;
723→}
