 1→export type CiState = "running" | "pass" | "fail" | "unknown";
 2→export type ReviewState = "approved" | "changes_requested" | "pending" | "none" | "unknown";
 3→
 4→export interface PrStateTransition {
 5→  type: "ci_passed" | "ci_failed" | "pr_approved" | "changes_requested";
 6→  branchName: string;
 7→  prNumber: number;
 8→  reviewer?: string;
 9→}
10→
11→export class PrStateTracker {
12→  private states: Map<string, { ci: CiState; review: ReviewState }>;
13→
14→  constructor() {
15→    this.states = new Map();
16→  }
17→
18→  update(repoId: string, branchName: string, prNumber: number, ci: CiState, review: ReviewState, reviewer?: string): PrStateTransition[] {
19→    const key = `${repoId}:${branchName}`;
20→    const prev = this.states.get(key);
21→    const transitions: PrStateTransition[] = [];
22→
23→    if (prev) {
24→      // CI transitions: only fire when moving from "running" to a terminal state
25→      if (prev.ci === "running" && ci === "pass") {
26→        transitions.push({ type: "ci_passed", branchName, prNumber });
27→      } else if (prev.ci === "running" && ci === "fail") {
28→        transitions.push({ type: "ci_failed", branchName, prNumber });
29→      }
30→
31→      // Review transitions: only fire when moving from "pending" to a terminal state
32→      if (prev.review === "pending" && review === "approved") {
33→        transitions.push({ type: "pr_approved", branchName, prNumber, reviewer });
34→      } else if (prev.review === "pending" && review === "changes_requested") {
35→        transitions.push({ type: "changes_requested", branchName, prNumber, reviewer });
36→      }
37→    }
38→
39→    this.states.set(key, { ci, review });
40→
41→    return transitions;
42→  }
43→}
