  4→const execFileAsync = promisify(execFile);
  5→
  6→export type NotifyUrgency = "low" | "normal" | "high";
  7→
  8→export interface NotifyBackend {
  9→  name: string;
 10→  available(): Promise<boolean>;
 11→  send(title: string, body: string, urgency: NotifyUrgency): Promise<boolean>;
 12→}
 13→
 14→async function isOnPath(binary: string): Promise<boolean> {
 15→  try {
 16→    await execFileAsync("which", [binary]);
 17→    return true;
 18→  } catch {
 19→    return false;
 20→  }
 21→}
 22→
 23→export class OpenclawBackend implements NotifyBackend {
 24→  readonly name = "openclaw";
 25→
 26→  async available(): Promise<boolean> {
 27→    return isOnPath("openclaw");
 28→  }
 29→
 30→  async send(title: string, body: string, _urgency: NotifyUrgency): Promise<boolean> {
 31→    try {
 32→      await execFileAsync("openclaw", ["wake", "--title", title, "--body", body]);
 33→      return true;
 34→    } catch {
 35→      return false;
 36→    }
 37→  }
 38→}
 39→
 40→export class MacOsNotifyBackend implements NotifyBackend {
 41→  readonly name = "macos-osascript";
 42→
 43→  async available(): Promise<boolean> {
 44→    return process.platform === "darwin";
 45→  }
 46→
 47→  async send(title: string, body: string, _urgency: NotifyUrgency): Promise<boolean> {
 48→    try {
 49→      const escaped_body = body.replace(/\\/g, "\\\\").replace(/"/g, '\\"');
 50→      const escaped_title = title.replace(/\\/g, "\\\\").replace(/"/g, '\\"');
 51→      const script = `display notification "${escaped_body}" with title "${escaped_title}"`;
 52→      await execFileAsync("osascript", ["-e", script]);
 53→      return true;
 54→    } catch {
 55→      return false;
 56→    }
 57→  }
 58→}
 59→
 60→export class LinuxNotifySendBackend implements NotifyBackend {
 61→  readonly name = "linux-notify-send";
 62→
 63→  async available(): Promise<boolean> {
 64→    return isOnPath("notify-send");
 65→  }
 66→
 67→  async send(title: string, body: string, urgency: NotifyUrgency): Promise<boolean> {
 68→    const urgencyMap: Record<NotifyUrgency, string> = {
 69→      low: "low",
 70→      normal: "normal",
 71→      high: "critical",
 72→    };
 73→
 74→    try {
 75→      await execFileAsync("notify-send", ["-u", urgencyMap[urgency], title, body]);
 76→      return true;
 77→    } catch {
 78→      return false;
 79→    }
 80→  }
 81→}
 82→
 83→export class TerminalBellBackend implements NotifyBackend {
 84→  readonly name = "terminal";
 85→
 86→  async available(): Promise<boolean> {
 87→    return true;
 88→  }
 89→
 90→  async send(title: string, body: string, _urgency: NotifyUrgency): Promise<boolean> {
 91→    try {
 92→      process.stderr.write("\x07");
 93→      process.stderr.write(`[${title}] ${body}\n`);
 94→      return true;
 95→    } catch {
 96→      return false;
 97→    }
 98→  }
 99→}
100→
101→const backendFactories: Record<string, () => NotifyBackend> = {
102→  openclaw: () => new OpenclawBackend(),
103→  "macos-osascript": () => new MacOsNotifyBackend(),
104→  "linux-notify-send": () => new LinuxNotifySendBackend(),
105→  terminal: () => new TerminalBellBackend(),
106→};
107→
108→export async function createBackends(configOrder: string[]): Promise<NotifyBackend[]> {
109→  const backends: NotifyBackend[] = [];
110→
111→  for (const name of configOrder) {
112→    const backendBuilder = backendFactories[name];
113→    if (!backendBuilder) {
114→      continue;
115→    }
116→
117→    const backend = backendBuilder();
118→    if (await backend.available()) {
119→      backends.push(backend);
120→    }
121→  }
122→
123→  return backends;
124→}
