 6→export interface NotificationService {
 7→  notify(title: string, body: string, urgency: NotifyUrgency): Promise<void>;
 8→  agentIdle(branchName: string): Promise<void>;
 9→  agentError(branchName: string, error: string): Promise<void>;
10→  ciPassed(branchName: string, prNumber: number): Promise<void>;
11→  ciFailed(branchName: string, prNumber: number): Promise<void>;
12→  prApproved(branchName: string, prNumber: number, reviewer: string): Promise<void>;
13→  changesRequested(branchName: string, prNumber: number, reviewer: string): Promise<void>;
14→  prMerged(branchName: string, prNumber: number): Promise<void>;
15→  taskCreated(branchName: string): Promise<void>;
16→}
17→
18→export function createNotificationService(backends: NotifyBackend[]): NotificationService {
19→  async function notify(title: string, body: string, urgency: NotifyUrgency): Promise<void> {
20→    for (const backend of backends) {
21→      const sent = await backend.send(title, body, urgency);
22→      if (sent) {
23→        return;
24→      }
25→    }
26→  }
27→
28→  return {
29→    notify,
30→
31→    async agentIdle(branchName: string): Promise<void> {
32→      await notify("Agent Idle", `Agent finished on ${branchName}`, "normal");
33→    },
34→
35→    async agentError(branchName: string, error: string): Promise<void> {
36→      await notify("Agent Error", `Agent error on ${branchName}: ${error}`, "high");
37→    },
38→
39→    async ciPassed(branchName: string, prNumber: number): Promise<void> {
40→      await notify("CI Passed", `CI passed on ${branchName} (PR #${prNumber})`, "low");
41→    },
42→
43→    async ciFailed(branchName: string, prNumber: number): Promise<void> {
44→      await notify("CI Failed", `CI failed on ${branchName} (PR #${prNumber})`, "high");
45→    },
46→
47→    async prApproved(branchName: string, prNumber: number, reviewer: string): Promise<void> {
48→      await notify("PR Approved", `PR #${prNumber} on ${branchName} approved by ${reviewer}`, "normal");
49→    },
50→
51→    async changesRequested(branchName: string, prNumber: number, reviewer: string): Promise<void> {
52→      await notify("Changes Requested", `Changes requested on PR #${prNumber} (${branchName}) by ${reviewer}`, "high");
53→    },
54→
55→    async prMerged(branchName: string, prNumber: number): Promise<void> {
56→      await notify("PR Merged", `PR #${prNumber} on ${branchName} merged`, "normal");
57→    },
58→
59→    async taskCreated(branchName: string): Promise<void> {
60→      await notify("Task Created", `New task on ${branchName}`, "low");
61→    },
62→  };
63→}
